function defaultCardForType(type) {
  if (type === "party")  return { headline: "Host your party here", body: "Croquet for up to 40 guests · pavilion hire · BYO catering", cta: "Enquire now", ctaTarget: "bookings", ctaUrl: "" };
  if (type === "join")   return { headline: "Come and play with us", body: "New players always welcome — no experience needed", cta: "Find out more", ctaTarget: "about", ctaUrl: "" };
  if (type === "event")  return { headline: "Entries now open", body: "Our annual club championship — all handicaps welcome", cta: "Enter now", ctaTarget: "external", ctaUrl: "" };
  return { headline: "", body: "", cta: "Learn more", ctaTarget: "about", ctaUrl: "" };
}


