const CW = 28, CL = 35;
const CW_DEFAULT = CW, CL_DEFAULT = CL; // regulation full court (yards) — editor default
const normX = x => x / CW;
const normY = y => 1 - (y / CL); // flip: south = bottom of court = top of SVG


// In GC: hoop 1 blue, hoop 3 red, all others white
function getHoopStroke(hoop, isGC, palHoop) {
  if (palHoop) return palHoop; // white/no-grass theme override
  if (isGC) {
    if (hoop.id === 1) return "#185FA5";
    if (hoop.id === 3) return "#B83232";
    return "#fff";
  }
  return hoop.stroke;
}


