// An admin (Secretary role) posts an announcement; every member sees it pinned to
// the top of their river when they next sign in. An announcement can optionally
// ask for an acknowledgement — a single tap that records the member has seen it.
// Prototype storage: a flat list in localStorage. The current member's id is "__me__".
const ANNOUNCEMENTS_KEY = "clubAnnouncements";
const ANN_ME = "__me__";

function loadAnnouncements() {
  try { return JSON.parse(localStorage.getItem(ANNOUNCEMENTS_KEY) || "[]"); }
  catch { return []; }
}
function saveAnnouncements(list) {
  try { localStorage.setItem(ANNOUNCEMENTS_KEY, JSON.stringify(list)); } catch {}
}
