function annTone(v) { return ANN_TONES.find(t => t.value === v) || ANN_TONES[0]; }

// Feedback announcements carry a `feedback` object that turns the card into a
// little response widget. Four kinds cover the common asks:
//   vote   — a quick Yes/No (or any 2 short options)
//   choice — pick one of several custom options ("what should we do?")
//   rating — a 1–5 star score ("what do you think?")
//   open   — free-text response ("what are we doing well?")
// Member responses are stored on the announcement under `responses` keyed by
// member id: { choice?, rating?, comment?, ts }.
const FEEDBACK_KINDS = [
  { id: "vote",   label: "Yes / No",       icon: "ti-thumb-up",      hint: "A quick two-way vote", color: "#0891B2" },
  { id: "choice", label: "Multiple choice", icon: "ti-list-check",   hint: "Pick one of your options", color: "#0891B2" },
  { id: "rating", label: "Rating",          icon: "ti-star",         hint: "A 1–5 star score", color: "#D97706" },
  { id: "open",   label: "Open response",   icon: "ti-message-dots", hint: "Free text in their own words", color: "#5A2D6B" },
];
function feedbackKind(id) { return FEEDBACK_KINDS.find(k => k.id === id) || FEEDBACK_KINDS[0]; }
// Tally responses for the secretary's results view.
function feedbackTally(ann) {
  const resp = ann.responses || {};
  const ids = Object.keys(resp);
  const fb = ann.feedback || {};
  const out = { total: ids.length, counts: {}, ratingSum: 0, ratingN: 0, comments: [] };
  ids.forEach(id => {
    const r = resp[id] || {};
    if ((fb.kind === "vote" || fb.kind === "choice") && r.choice != null) {
      out.counts[r.choice] = (out.counts[r.choice] || 0) + 1;
    }
    if (fb.kind === "rating" && typeof r.rating === "number") { out.ratingSum += r.rating; out.ratingN += 1; }
    if (r.comment && r.comment.trim()) out.comments.push({ id, comment: r.comment.trim(), ts: r.ts });
  });
  out.ratingAvg = out.ratingN ? out.ratingSum / out.ratingN : 0;
  return out;
}


// Drag-to-scroll for horizontal overflow rows (desktop mouse can't pan them otherwise).
// Returns a ref to attach to the scroll container. Touch/trackpad still work natively.
// A small movement threshold means taps/clicks on inner buttons still fire normally.
function useDragScroll() {
  const ref = React.useRef(null);
  React.useEffect(() => {
    const el = ref.current;
    if (!el) return;
    let down = false, moved = false, startX = 0, startLeft = 0;
    const THRESH = 5;

    function onDown(e) {
      // Only primary mouse button; ignore touch (native scroll handles it)
      if (e.pointerType === "touch" || e.button !== 0) return;
      down = true; moved = false;
      startX = e.clientX;
      startLeft = el.scrollLeft;
    }
    function onMove(e) {
      if (!down) return;
      const dx = e.clientX - startX;
      if (!moved && Math.abs(dx) > THRESH) {
        moved = true;
        el.style.cursor = "grabbing";
        el.style.userSelect = "none";
      }
      if (moved) {
        el.scrollLeft = startLeft - dx;
        e.preventDefault();
      }
    }
    function endDrag(e) {
      if (!down) return;
      down = false;
      el.style.cursor = "";
      el.style.userSelect = "";
      // Swallow the click that follows a real drag so buttons don't fire
      if (moved) {
        const swallow = ev => { ev.stopPropagation(); ev.preventDefault(); };
        el.addEventListener("click", swallow, { capture: true, once: true });
        // Safety: remove if no click arrives
        setTimeout(() => el.removeEventListener("click", swallow, { capture: true }), 50);
      }
      moved = false;
    }

    el.addEventListener("pointerdown", onDown);
    window.addEventListener("pointermove", onMove, { passive: false });
    window.addEventListener("pointerup", endDrag);
    return () => {
      el.removeEventListener("pointerdown", onDown);
      window.removeEventListener("pointermove", onMove);
      window.removeEventListener("pointerup", endDrag);
    };
  }, []);
  return ref;
}

// ─── SwipeFade — wraps a horizontally-scrolling strip and shows edge fades only
// when there's more content to scroll to in that direction. Used on overflowing
// tab/menu strips so it's clear they're swipeable. Children render inside the
// scroll container; pass the strip's flex styles via `trackStyle`.
function SwipeFade({ children, trackStyle = {}, fadeColor, leftWidth = 24, rightWidth = 28, className, dataActive }) {
  const scrollRef = useDragScroll();
  const [scrolled, setScrolled] = React.useState(false);
  const [atEnd, setAtEnd] = React.useState(true);
  const col = fadeColor || T.pageBg;

  React.useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    function update() {
      setScrolled(el.scrollLeft > 8);
      // atEnd is true when there's no more to scroll (also when content fits).
      setAtEnd(el.scrollLeft + el.clientWidth >= el.scrollWidth - 8);
    }
    el.addEventListener("scroll", update, { passive: true });
    update();
    let ro;
    if (typeof ResizeObserver !== "undefined") {
      ro = new ResizeObserver(update);
      ro.observe(el);
      if (el.firstElementChild) ro.observe(el.firstElementChild);
    }
    window.addEventListener("resize", update);
    return () => {
      el.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
      if (ro) ro.disconnect();
    };
  }, []);

  return (
    <div style={{ position: "relative" }}>
      {scrolled && (
        <div aria-hidden="true" style={{ position: "absolute", top: 0, left: 0, bottom: 0, width: leftWidth, zIndex: 2, pointerEvents: "none",
          background: `linear-gradient(to right, ${col}, transparent)` }} />
      )}
      {!atEnd && (
        <div aria-hidden="true" style={{ position: "absolute", top: 0, right: 0, bottom: 0, width: rightWidth, zIndex: 2, pointerEvents: "none",
          background: `linear-gradient(to left, ${col}, transparent)` }} />
      )}
      <div ref={scrollRef} className={className} data-active={dataActive}
        style={{ display: "flex", overflowX: "auto", scrollbarWidth: "none", msOverflowStyle: "none", WebkitOverflowScrolling: "touch", ...trackStyle }}>
        {children}
      </div>
    </div>
  );
}

// ─── RichText — renders a safe lightweight-markup subset to React elements ─────
// Supported (Markdown-style), authored as plain text so it still pastes/stores
// cleanly: "# / ## / ###" headers, "**bold**", "*italic*" (or _italic_),
// "- " / "* " bullet lists, "1. " numbered lists, and blank-line paragraphs.
// No HTML is ever injected — everything is parsed to elements, so it's XSS-safe.
function rtInline(text, keyPrefix) {
  // Split on **bold**, *italic*/_italic_, leaving plain runs between.
  const out = [];
  const re = /(\*\*([^*]+)\*\*|\*([^*]+)\*|_([^_]+)_)/g;
  let last = 0, m, i = 0;
  while ((m = re.exec(text)) !== null) {
    if (m.index > last) out.push(text.slice(last, m.index));
    if (m[2] != null) out.push(<strong key={`${keyPrefix}-b${i}`}>{m[2]}</strong>);
    else out.push(<em key={`${keyPrefix}-i${i}`}>{m[3] != null ? m[3] : m[4]}</em>);
    last = m.index + m[0].length; i++;
  }
  if (last < text.length) out.push(text.slice(last));
  return out;
}
function RichText({ text, color, size = 12.5, muted }) {
  if (!text) return null;
  const baseColor = color || (muted ? T.textMuted : T.text);
  const lines = String(text).replace(/\r\n/g, "\n").split("\n");
  const blocks = [];
  let i = 0;
  const headerSizes = { 1: size + 5, 2: size + 2.5, 3: size + 1 };
  while (i < lines.length) {
    const line = lines[i];
    const trimmed = line.trim();
    if (trimmed === "") { i++; continue; }
    // Headers
    const h = trimmed.match(/^(#{1,3})\s+(.*)$/);
    if (h) {
      const lvl = h[1].length;
      blocks.push(
        <p key={`h${i}`} style={{ margin: blocks.length ? "10px 0 4px" : "0 0 4px", fontSize: headerSizes[lvl], fontWeight: 700, color: baseColor, lineHeight: 1.3 }}>
          {rtInline(h[2], `h${i}`)}
        </p>
      );
      i++; continue;
    }
    // Unordered list
    if (/^[-*]\s+/.test(trimmed)) {
      const items = [];
      while (i < lines.length && /^\s*[-*]\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\s*[-*]\s+/, "")); i++;
      }
      blocks.push(
        <ul key={`ul${i}`} style={{ margin: "4px 0", paddingLeft: 20, color: baseColor, fontSize: size, lineHeight: 1.55 }}>
          {items.map((it, j) => <li key={j} style={{ marginBottom: 2 }}>{rtInline(it, `ul${i}-${j}`)}</li>)}
        </ul>
      );
      continue;
    }
    // Ordered list
    if (/^\d+\.\s+/.test(trimmed)) {
      const items = [];
      while (i < lines.length && /^\s*\d+\.\s+/.test(lines[i])) {
        items.push(lines[i].replace(/^\s*\d+\.\s+/, "")); i++;
      }
      blocks.push(
        <ol key={`ol${i}`} style={{ margin: "4px 0", paddingLeft: 22, color: baseColor, fontSize: size, lineHeight: 1.55 }}>
          {items.map((it, j) => <li key={j} style={{ marginBottom: 2 }}>{rtInline(it, `ol${i}-${j}`)}</li>)}
        </ol>
      );
      continue;
    }
    // Paragraph — gather consecutive non-blank, non-block lines (soft line breaks kept)
    const para = [];
    while (i < lines.length && lines[i].trim() !== "" && !/^(#{1,3})\s+/.test(lines[i].trim()) && !/^\s*[-*]\s+/.test(lines[i]) && !/^\s*\d+\.\s+/.test(lines[i])) {
      para.push(lines[i]); i++;
    }
    blocks.push(
      <p key={`p${i}`} style={{ margin: blocks.length ? "6px 0 0" : 0, fontSize: size, color: baseColor, lineHeight: 1.6 }}>
        {para.map((ln, j) => (
          <React.Fragment key={j}>{rtInline(ln, `p${i}-${j}`)}{j < para.length - 1 ? <br /> : null}</React.Fragment>
        ))}
      </p>
    );
  }
  return <div>{blocks}</div>;
}


