// Renders all four corner flags with a soft pennant drop-shadow and pole-foot
// shadow on the grass. `idSuffix` keeps the SVG filter id unique per diagram.
function IsoFlags({ idSuffix }) {
  const fid = `iso-flagshadow-${idSuffix}`;
  // Project the flag-centre (tx,ty) from raw lawn-asset space into screen space so
  // the numerals can be drawn flat on the screen (outside ISO_TRANSFORM), upright
  // and unscaled, rather than painted onto the lawn plane.
  const toScreen = (ax, ay) => ({
    sx: ISO_OX + (ax - ISO_ORIG_X0) * ISO_SCALE,
    sy: ISO_OY + (ay - ISO_ORIG_Y0) * ISO_SCALE,
  });
  return (
    <>
      {/* Poles + pennants live on the lawn plane (ISO_TRANSFORM) */}
      <g transform={ISO_TRANSFORM}>
        <defs>
          <filter id={fid} x="-40%" y="-40%" width="180%" height="200%">
            <feDropShadow dx="2.4" dy="5" stdDeviation="2.6" floodColor="#000" floodOpacity="0.34"/>
          </filter>
        </defs>
        {ISO_FLAG_DATA.map((f, i) => (
          <g key={i}>
            {/* shadow pooled at the foot of the pole on the grass */}
            <ellipse cx={f.baseX} cy={f.baseY + 2} rx="9" ry="3.4" fill="rgba(0,0,0,0.26)"/>
            <g filter={`url(#${fid})`}>
              <path d={f.pole} fill="#ffffff" stroke="#c9cdd2" strokeWidth="0.6"/>
              <path d={f.flag} fill={f.fill}/>
            </g>
          </g>
        ))}
      </g>
      {/* Numerals drawn flat on the screen — no iso transform, constant size */}
      {ISO_FLAG_DATA.map((f, i) => {
        const { sx, sy } = toScreen(f.tx, f.ty);
        return (
          <text key={i} x={sx} y={sy} fontSize="11" fontWeight="700" fontFamily="sans-serif"
            textAnchor="middle" fill={f.numFill || "#fff"} opacity="0.95"
            style={{ paintOrder: "stroke" }} stroke="rgba(0,0,0,0.35)" strokeWidth="0.5">{f.num}</text>
        );
      })}
    </>
  );
}

// Lighten a #rrggbb colour toward white by frac (0..1) — used for ball sphere highlight
function _isoLighten(hex, frac) {
  const m = /^#?([0-9a-f]{6})$/i.exec(hex || "");
  if (!m) return hex;
  const n = parseInt(m[1], 16);
  let r = (n >> 16) & 255, g = (n >> 8) & 255, b = n & 255;
  r = Math.round(r + (255 - r) * frac);
  g = Math.round(g + (255 - g) * frac);
  b = Math.round(b + (255 - b) * frac);
  return `#${((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1)}`;
}
// A glossy ball: cast shadow on the grass + a colour radial gradient sphere whose
// focal highlight sits upper-left, matching the source MCC ball styling.
function IsoBallSphere({ x, y, r, color, gid }) {
  const hi = _isoLighten(color, 0.55);
  return (
    <g>
      <defs>
        <radialGradient id={gid} cx="36%" cy="30%" r="75%">
          <stop offset="0%" stopColor={hi}/>
          <stop offset="60%" stopColor={color}/>
          <stop offset="100%" stopColor={_isoLighten(color, -0.18)}/>
        </radialGradient>
      </defs>
      {/* cast shadow, offset down-right and flattened */}
      <ellipse cx={x + r * 0.35} cy={y + r * 0.62} rx={r * 1.05} ry={r * 0.42} fill="rgba(0,0,0,0.30)"/>
      {/* sphere */}
      <circle cx={x} cy={y} r={r} fill={`url(#${gid})`} stroke="rgba(0,0,0,0.28)" strokeWidth="0.8"/>
      {/* small specular dot */}
      <circle cx={x - r * 0.32} cy={y - r * 0.34} r={r * 0.22} fill="#fff" opacity="0.55"/>
    </g>
  );
}
function IsoHoop({ h }) {
  return (
    <g transform={ISO_TRANSFORM}>
      {h.paths.map((p,i) => <path key={i} d={p.d} stroke={p.stroke||"none"} strokeWidth={p.sw||0} fill={p.fill||"none"} fillOpacity={p.fillOpacity||1}/>)}
    </g>
  );
}
function IsoPeg() {
  return (
    <g transform={ISO_TRANSFORM}>
      {ISO_PEG_DATA.paths.map((p,i) => <path key={i} d={p.d} stroke={p.stroke||"none"} strokeWidth={p.sw||0} fill={p.fill||"none"} fillOpacity={p.fillOpacity||1}/>)}
    </g>
  );
}
function IsoBall({ b, keyPfx }) {
  const { x, y } = isoXY(b.col, b.row);
  const r = 6;
  const gid = `${keyPfx}-ball-${b.color.replace('#','')}`;
  return <IsoBallSphere x={x} y={y} r={r} color={b.color} gid={gid}/>;
}
function buildDepthSorted(ballList, keyPfx) {
  const items = [];
  ISO_HOOP_DATA.forEach(h => items.push({y: h.depthY, el: <IsoHoop key={h.key} h={h}/>}));
  items.push({y: ISO_PEG_DATA.depthY, el: <IsoPeg key="peg"/>});
  ballList.forEach((b,i) => { const {y} = isoXY(b.col, b.row); items.push({y, el: <IsoBall key={`${keyPfx}-b-${i}`} b={b} keyPfx={keyPfx}/>}); });
  items.sort((a,b) => a.y - b.y);
  return items.map(it => it.el);
}

// ─── Editor isometric view presets ───────────────────────────────────────────
// Presentation-mode camera angles for the live snapshot canvas. Each projects the
// flat lawn group onto a tilted plane via an SVG matrix, applied around the lawn
// centre (cx,cy). These are view-only (top-down remains the editing view).
// The transform tilts depth (foreshortens Y) and skews so the lawn reads as 3-D.
//   matrix(a,b,c,d,e,f): we build it from a Y-foreshorten (ky), an X-skew (kx),
//   and an optional rotation feel. Kept simple and readable per preset.
const ISO_VIEWS = [
  { key: "iso",     label: "Isometric", icon: "ti-cube",          ky: 0.86, kx: -0.50, rot: 30,  desc: "True isometric — lawn as a diamond." },
  { key: "subtle",  label: "Tilt",      icon: "ti-perspective",   ky: 0.82, kx: 0.18, rot: 0,   desc: "Gentle perspective." },
  { key: "coach",   label: "Coaching",  icon: "ti-school",        ky: 0.52, kx: 0.62, rot: -6,  desc: "Matches diagram angle." },
];
// Resolve a view spec that may be a key (string) into ISO_VIEWS, or already be a
// view object {kx,ky,rot}. Returns null for top-down (null/undefined).
function resolveIsoView(spec) {
  if (!spec) return null;
  if (typeof spec === "object") return spec;
  return ISO_VIEWS.find(z => z.key === spec) || null;
}
// Build the SVG transform string for an iso view about a centre point.
function isoViewTransform(viewSpec, cx, cy) {
  const v = resolveIsoView(viewSpec);
  if (!v) return undefined;
  // translate to origin → rotate → skewX → scaleY → translate back
  const parts = [
    `translate(${cx}, ${cy})`,
    v.rot ? `rotate(${v.rot})` : "",
    `matrix(1, 0, ${v.kx}, ${v.ky}, 0, 0)`,
    `translate(${-cx}, ${-cy})`,
  ];
  return parts.filter(Boolean).join(" ");
}
// Project a point through the same transform isoViewTransform builds, about (cx,cy):
//   p' = T(cx,cy) · R(rot) · [[1,kx],[0,ky]] · T(-cx,-cy) · p
function isoProjectPoint(v, cx, cy, x, y) {
  // translate to origin
  let px = x - cx, py = y - cy;
  // skew/scale: matrix(1,0,kx,ky,0,0) → x' = x + kx*y ; y' = ky*y
  let sx = px + v.kx * py;
  let sy = v.ky * py;
  // rotate
  const r = (v.rot || 0) * Math.PI / 180, cos = Math.cos(r), sin = Math.sin(r);
  const rx = sx * cos - sy * sin;
  const ry = sx * sin + sy * cos;
  // translate back
  return { x: rx + cx, y: ry + cy };
}
// Axis-aligned bounding box of a [0,0,w,h] rect projected through an iso view,
// about centre (cx,cy). Returns {minX,minY,maxX,maxY}. Top-down → identity box.
function isoViewBBox(viewSpec, w, h, cx, cy) {
  const v = resolveIsoView(viewSpec);
  if (!v) return { minX: 0, minY: 0, maxX: w, maxY: h };
  const corners = [[0, 0], [w, 0], [w, h], [0, h]].map(([x, y]) => isoProjectPoint(v, cx, cy, x, y));
  const xs = corners.map(c => c.x), ys = corners.map(c => c.y);
  return { minX: Math.min(...xs), minY: Math.min(...ys), maxX: Math.max(...xs), maxY: Math.max(...ys) };
}


// ─── IsometricLawnDiagram ─────────────────────────────────────────────────────
function IsometricLawnDiagram({ data, grassStyle = "diamond", grassColor = "green", scene = "none" }) {
  // Calibrated isometric transform from actual SVG lawn asset
  // Lawn: 28 cols (W→E) × 35 rows (S→N). Corners: I=SW, II=NW, III=NE, IV=SE
  // Least-squares fit to corner flags + interior landmarks:
  const SCALE = ISO_SCALE, OX = ISO_OX, OY = ISO_OY, ORIG_X0 = ISO_ORIG_X0, ORIG_Y0 = ISO_ORIG_Y0;
  const iso = isoXY;

  const balls = data.balls || [];
  const arrows = data.arrows || [];
  const annotations = data.annotations || [];

  // Unique arrow colours for markers
  const arrowColors = [...new Set(arrows.map(a => a.color))];

  function Ball({ col, row, color, label }) {
    const { x, y } = iso(col, row);
    return <IsoBallSphere x={x} y={y} r={6} color={color} gid={`iso-ball-${color.replace('#','')}`}/>;
  }

  function Arrow({ c1, r1, c2, r2, color, dashed }) {
    const p1 = iso(c1, r1), p2 = iso(c2, r2);
    const mx = (p1.x + p2.x) / 2, my = (p1.y + p2.y) / 2 - 18;
    const id = `iso-a-${color.replace('#', '')}`;
    return (
      <path d={`M${p1.x},${p1.y} Q${mx},${my} ${p2.x},${p2.y}`}
        fill="none" stroke={color} strokeWidth="2"
        strokeDasharray={dashed ? "6,3" : "none"}
        markerEnd={`url(#${id})`} opacity="0.92"/>
    );
  }


  return (
    <div style={{ borderRadius: 8, overflow: "hidden", border: "1px solid #D8D4CC" }}>
      <svg viewBox="0 0 640 420" style={{ width: "100%", display: "block" }} xmlns="http://www.w3.org/2000/svg">
        <defs>
          {arrowColors.map(c => (
            <marker key={c} id={`iso-a-${c.replace('#','')}`}
              markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
              <path d="M0,0 L0,6 L6,3 z" fill={c}/>
            </marker>
          ))}
        </defs>

        {/* Scene backdrop (surroundings) behind everything */}
        <SceneBackdrop scene={scene} x={0} y={0} w={640} h={420} grassColor={grassColor} idSuffix="isobg" iso mccTransform={ISO_TRANSFORM}/>

        {/* Grass fill clipped to lawn diamond */}
        <defs>
          <clipPath id="iso-lawn-clip">
            <polygon points="29,229 404,32 611,172 236,412"/>
          </clipPath>
        </defs>
        <g clipPath="url(#iso-lawn-clip)">
          <GrassPattern style={grassStyle} color={grassColor} vw={640} vh={420} idSuffix="iso"/>
          <DayNightLawnRect vw={640} vh={420} />
        </g>

        {/* Base lawn SVG scaled and translated to fit */}
        <g transform={`translate(${OX - ORIG_X0 * SCALE}, ${OY - ORIG_Y0 * SCALE}) scale(${SCALE})`}>
          {/* Soil south edge */}
          <path d="M786.95 1063.73l915-585v20l-915 590z" stroke="#666" strokeWidth="2" fill="#936222" fillOpacity=".74"/>
          {/* Soil west edge */}
          <path d="M281.95 643.73v-25l98.68 86.96 107.72 94.9 210.23 185.26 88.37 77.87v25l-100.77-88.8-238.5-210.16-99.58-87.74z" stroke="#666" strokeWidth="2" fill="url(#iso-f)"/>
          {/* Boundary stroke */}
          <path d="M281.36 618.26l915-480 505 340-915 585z" stroke="#666" strokeWidth="2" fill="none"/>
          {/* Stripe gradient defs (soil only) */}
          <defs>
            <linearGradient gradientUnits="userSpaceOnUse" id="iso-f" x1="786.95" y1="618.73" x2="359.64" y2="1088.73"><stop offset="32.35%" stopColor="#db8d26" stopOpacity=".74"/><stop offset="60.08%" stopColor="#936222" stopOpacity=".74"/><stop offset="100%" stopColor="#5f3f16" stopOpacity=".74"/></linearGradient>
          </defs>
        </g>

        {/* Corner flags (own ISO_TRANSFORM, with shadow + numerals) */}
        <IsoFlags idSuffix="iso"/>

        {/* Depth-sorted overlays: arrows first, then hoops/peg/balls sorted by Y */}
        {arrows.map((a, i) => (
          <Arrow key={i} c1={a.c1} r1={a.r1} c2={a.c2} r2={a.r2} color={a.color} dashed={a.dashed}/>
        ))}
        {buildDepthSorted(balls, "iso")}
        {annotations.map((a, i) => {
          const { x, y } = iso(a.col, a.row);
          const w = a.text.length * 6 + 12;
          return (
            <g key={i}>
              <rect x={x - 4} y={y - 23} width={w} height={15} rx="3"
                fill="rgba(10,30,18,0.82)" stroke="rgba(255,255,255,0.25)" strokeWidth="0.5"/>
              <text x={x + 2} y={y - 12} fontSize="10" fill="rgba(255,255,255,0.95)"
                fontFamily="sans-serif" fontWeight="600">{a.text}</text>
            </g>
          );
        })}
        {data.title && (() => {
          const w = data.title.length * 7.5 + 20;
          return (
            <g>
              <rect x="14" y="12" width={w} height="22" rx="4"
                fill="rgba(10,30,18,0.78)" stroke="rgba(255,255,255,0.18)" strokeWidth="1"/>
              <text x="22" y="28" fontSize="11" fill="white" fontFamily="sans-serif" fontWeight="700">{data.title}</text>
            </g>
          );
        })()}
      </svg>
    </div>
  );
}

// ─── AnimatedIsometricDiagram ─────────────────────────────────────────────────
function AnimatedIsometricDiagram({ data, grassStyle = "diamond", grassColor = "green", scene = "none" }) {
  const steps = data.steps || [];
  const total = steps.length;

  // Physical model: balls are hit at t=0, travel with ease-out (fast start, decelerates)
  // Duration scales with pixel distance — longer shots take proportionally longer
  const BASE_SPEED  = 120; // px/s at "standard" 80px shot
  const MIN_DUR     = 400; // ms — very short shots
  const MAX_DUR     = 2200; // ms — very long shots
  const PAUSE_DUR   = 600; // ms pause at each step before moving to next

  const tMsRef     = React.useRef(0); // ms elapsed within current transition
  const stepRef    = React.useRef(0); // which transition we're in (0 = step0→step1)
  const phaseRef   = React.useRef("move"); // "move" | "pause"
  const playingRef = React.useRef(false);
  const rafRef     = React.useRef(null);
  const lastTsRef  = React.useRef(null);

  const [renderState, setRenderState] = React.useState({ step: 0, frac: 0, phase: "move" });
  const [playing, setPlaying] = React.useState(false);

  // Ease-out cubic: starts fast, decelerates to stop — mallet physics
  function easeOut(t) { return 1 - Math.pow(1 - t, 3); }

  // Calculate transition duration based on max ball travel distance
  function getTransitionDur(fromIdx, toIdx) {
    const from = steps[fromIdx], to = steps[Math.min(toIdx, total - 1)];
    let maxDist = 0;
    from.balls.forEach(fb => {
      const tb = to.balls.find(b => b.color === fb.color) || fb;
      const fp = isoXY(fb.col, fb.row), tp = isoXY(tb.col, tb.row);
      const d = Math.hypot(tp.x - fp.x, tp.y - fp.y);
      if (d > maxDist) maxDist = d;
    });
    // Scale duration by distance: ~80px = 1x, very short=min, very long=max
    const dur = Math.round((maxDist / 80) * (MAX_DUR - MIN_DUR) + MIN_DUR);
    return Math.min(MAX_DUR, Math.max(MIN_DUR, dur));
  }

  function tick(ts) {
    if (!playingRef.current) return;
    if (lastTsRef.current == null) lastTsRef.current = ts;
    const dt = ts - lastTsRef.current;
    lastTsRef.current = ts;

    tMsRef.current += dt;

    const curDur = phaseRef.current === "pause"
      ? PAUSE_DUR
      : getTransitionDur(stepRef.current, stepRef.current + 1);

    if (tMsRef.current >= curDur) {
      tMsRef.current = 0;
      if (phaseRef.current === "move") {
        phaseRef.current = "pause";
        stepRef.current = Math.min(stepRef.current + 1, total - 1);
        setRenderState({ step: stepRef.current, frac: 1, phase: "pause" });
        if (stepRef.current >= total - 1) {
          playingRef.current = false;
          setPlaying(false);
          return;
        }
      } else {
        phaseRef.current = "move";
        setRenderState({ step: stepRef.current, frac: 0, phase: "move" });
      }
    } else {
      const rawFrac = tMsRef.current / curDur;
      setRenderState({
        step: stepRef.current,
        frac: phaseRef.current === "move" ? rawFrac : 1,
        phase: phaseRef.current,
      });
    }

    rafRef.current = requestAnimationFrame(tick);
  }

  function startPlay() {
    if (stepRef.current >= total - 1) { stepRef.current = 0; tMsRef.current = 0; phaseRef.current = "move"; }
    lastTsRef.current = null;
    playingRef.current = true;
    setPlaying(true);
    rafRef.current = requestAnimationFrame(tick);
  }
  function pause() {
    playingRef.current = false;
    setPlaying(false);
    cancelAnimationFrame(rafRef.current);
  }
  function togglePlay() { playing ? pause() : startPlay(); }
  function goToStep(i) {
    pause();
    stepRef.current = i;
    tMsRef.current = 0;
    phaseRef.current = "pause";
    setRenderState({ step: i, frac: 1, phase: "pause" });
  }

  React.useEffect(() => () => cancelAnimationFrame(rafRef.current), []);

  // Rendering
  const { step: rStep, frac: rawFrac, phase } = renderState;
  const fromIdx = phase === "move" ? rStep : rStep;
  const toIdx   = Math.min(rStep + 1, total - 1);
  const ef      = easeOut(Math.max(0, Math.min(1, rawFrac)));
  const fromStep= steps[fromIdx];
  const toStep  = steps[toIdx];
  const dispStep= rStep;
  const curStep = steps[dispStep];

  // Per-ball: only the ball that MOVED (has arrow) gets ease-out; stationary balls don't jitter
  const interpBalls = fromStep.balls.map(fb => {
    const tb = toStep.balls.find(b => b.color === fb.color) || fb;
    const fp = isoXY(fb.col, fb.row), tp = isoXY(tb.col, tb.row);
    const dist = Math.hypot(tp.x - fp.x, tp.y - fp.y);
    // If ball barely moved (< 3px), snap to destination to avoid floating-point jitter
    const t = dist < 3 ? 1 : ef;
    return { color: fb.color, x: fp.x + (tp.x - fp.x) * t, y: fp.y + (tp.y - fp.y) * t };
  });

  const arrowOpacity = phase === "move" ? Math.min(1, rawFrac * 3) : (1 - Math.min(1, (rawFrac - 0.5) * 4));

  function buildInterpolatedDepthSorted() {
    const items = [];
    ISO_HOOP_DATA.forEach(h => items.push({ y: h.depthY, el: <IsoHoop key={h.key} h={h}/> }));
    items.push({ y: ISO_PEG_DATA.depthY, el: <IsoPeg key="peg"/> });
    interpBalls.forEach((b, i) => {
      const gid = `anim-iball-${b.color.replace('#','')}`;
      items.push({ y: b.y, el: (
        <IsoBallSphere key={`ib-${i}`} x={b.x} y={b.y} r={6} color={b.color} gid={gid}/>
      )});
    });
    items.sort((a, b) => a.y - b.y);
    return items.map(it => it.el);
  }

  const arrowStep = phase === "move" ? fromStep : toStep;
  const OX = ISO_OX, OY = ISO_OY, ORIG_X0 = ISO_ORIG_X0, ORIG_Y0 = ISO_ORIG_Y0, SCALE = ISO_SCALE;

  return (
    <div style={{ borderRadius: 8, overflow: "hidden", border: "1px solid #D8D4CC" }}>
      <svg viewBox="0 0 640 420" style={{ width: "100%", display: "block" }} xmlns="http://www.w3.org/2000/svg">
        <rect width="640" height="420" fill="#fff"/>
        <SceneBackdrop scene={scene} x={0} y={0} w={640} h={420} grassColor={grassColor} idSuffix="animbg" iso mccTransform={ISO_TRANSFORM}/>
        <defs>
          {["#185FA5","#B83232","#2C2C2A","#C49A0A"].map(c => (
            <marker key={c} id={`anim-a-${c.replace('#','')}`} markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
              <path d="M0,0 L0,6 L6,3 z" fill={c}/>
            </marker>
          ))}
          <clipPath id="anim-lawn-clip">
            <polygon points="29,229 404,32 611,172 236,412"/>
          </clipPath>
        </defs>

        <g clipPath="url(#anim-lawn-clip)">
          <GrassPattern style={grassStyle} color={grassColor} vw={640} vh={420} idSuffix="anim"/>
          <DayNightLawnRect vw={640} vh={420} />
        </g>

        <g transform={`translate(${OX - ORIG_X0 * SCALE}, ${OY - ORIG_Y0 * SCALE}) scale(${SCALE})`}>
          <path d="M786.95 1063.73l915-585v20l-915 590z" stroke="#666" strokeWidth="2" fill="#936222" fillOpacity=".74"/>
          <path d="M281.95 643.73v-25l98.68 86.96 107.72 94.9 210.23 185.26 88.37 77.87v25l-100.77-88.8-238.5-210.16-99.58-87.74z" stroke="#666" strokeWidth="2" fill="url(#aiso-f)"/>
          <path d="M281.36 618.26l915-480 505 340-915 585z" stroke="#666" strokeWidth="2" fill="none"/>
          <defs>
            <linearGradient gradientUnits="userSpaceOnUse" id="aiso-f" x1="786.95" y1="618.73" x2="359.64" y2="1088.73"><stop offset="32.35%" stopColor="#db8d26" stopOpacity=".74"/><stop offset="60.08%" stopColor="#936222" stopOpacity=".74"/><stop offset="100%" stopColor="#5f3f16" stopOpacity=".74"/></linearGradient>
          </defs>
        </g>

        {/* Corner flags (own ISO_TRANSFORM, with shadow + numerals) */}
        <IsoFlags idSuffix="anim"/>

        {arrowStep && arrowStep.arrow && (() => {
          const col = arrowStep.arrow.color;
          const p1 = isoXY(arrowStep.arrow.c1, arrowStep.arrow.r1);
          const p2 = isoXY(arrowStep.arrow.c2, arrowStep.arrow.r2);
          const mx = (p1.x + p2.x) / 2, my = (p1.y + p2.y) / 2 - 16;
          return (
            <path d={`M${p1.x},${p1.y} Q${mx},${my} ${p2.x},${p2.y}`}
              fill="none" stroke={col} strokeWidth="1.5"
              strokeDasharray={arrowStep.arrow.dashed ? "5,3" : "6,3"}
              opacity={arrowOpacity} markerEnd={`url(#anim-a-${col.replace('#','')})`}/>
          );
        })()}

        {buildInterpolatedDepthSorted()}

        <rect x="14" y="370" width="612" height="40" rx="5" fill="#1A4A2E"/>
        <text x="22" y="387" fontSize="11" fontWeight="700" fill="white" fontFamily="sans-serif">{curStep.label}</text>
        <text x="22" y="403" fontSize="10" fill="rgba(255,255,255,0.65)" fontFamily="sans-serif">{curStep.note}</text>

        <g>
          <g onClick={() => goToStep(Math.max(0, dispStep - 1))} style={{ cursor: dispStep > 0 ? "pointer" : "default" }} opacity={dispStep > 0 ? 1 : 0.3}>
            <circle cx={560} cy={22} r={11} fill="#1A4A2E" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
            <path d="M564,17 L559,22 L564,27" fill="none" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          </g>
          <g onClick={togglePlay} style={{ cursor: "pointer" }}>
            <circle cx={584} cy={22} r={11} fill="#1A4A2E" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
            {playing
              ? <><rect x="580" y="17" width="3" height="10" rx="1" fill="white"/><rect x="585" y="17" width="3" height="10" rx="1" fill="white"/></>
              : <path d="M581,17 L581,27 L590,22 Z" fill="white"/>
            }
          </g>
          <g onClick={() => goToStep(Math.min(total - 1, dispStep + 1))} style={{ cursor: dispStep < total - 1 ? "pointer" : "default" }} opacity={dispStep < total - 1 ? 1 : 0.3}>
            <circle cx={608} cy={22} r={11} fill="#1A4A2E" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
            <path d="M604,17 L609,22 L604,27" fill="none" stroke="white" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
          </g>
          {steps.map((_, i) => (
            <circle key={i} cx={560 + i * 16} cy={44} r={4}
              fill={i === dispStep ? "#1A4A2E" : "rgba(26,74,46,0.2)"}
              style={{ cursor: "pointer" }}
              onClick={() => goToStep(i)}/>
          ))}
        </g>

        {data.title && (() => {
          const w = data.title.length * 7.5 + 20;
          return (
            <g>
              <rect x="14" y="12" width={w} height="22" rx="4" fill="#1A4A2E" stroke="rgba(255,255,255,0.15)" strokeWidth="1"/>
              <text x="22" y="28" fontSize="11" fill="white" fontFamily="sans-serif" fontWeight="700">{data.title}</text>
            </g>
          );
        })()}
      </svg>
    </div>
  );
}

// ─── StrategyDiagram ──────────────────────────────────────────────────────────
// Derive animation duration string from stored animSpeed — used by StrategyDiagram, BallPositionRecorder, SnapshotCard
function animDuration(a, type) {
  const speed = a?.animSpeed || "normal";
  if (type === "march") return speed === "slow" ? "90s" : speed === "fast" ? "9s" : "22s";
  if (type === "flow")  return speed === "slow" ? "60s" : speed === "fast" ? "6s" : "15s";
  return "1s";
}

function StrategyDiagram({ diagram, title, grassStyle = "diamond", grassColor = "green", grassLength = "none", grubLevel = "none", waterLevel = "none", scene = "none" }) {
  if (!diagram && !title) return null;

  // Load from localStorage if a custom version has been saved
  const [customDiag, setCustomDiag] = React.useState(() => {
    if (!title) return null;
    try { const s = localStorage.getItem(strategyDiagramKey(title)); return s ? JSON.parse(s) : null; } catch { return null; }
  });

  // Re-read when title changes
  React.useEffect(() => {
    if (!title) return;
    try { const s = localStorage.getItem(strategyDiagramKey(title)); setCustomDiag(s ? JSON.parse(s) : null); } catch {}
  }, [title]);

  const src = customDiag || diagram;
  if (!src) return null;

  const VW = 220;
  const VH = Math.round(VW * 35 / 28);
  const ydU = VW / 28;
  const pal = GRASS_COLORS[grassColor] || GRASS_COLORS.green;

  const hoops = [
    { id:1, nx:7/28,  ny:1-7/35  },
    { id:2, nx:7/28,  ny:1-28/35 },
    { id:3, nx:21/28, ny:1-28/35 },
    { id:4, nx:21/28, ny:1-7/35  },
    { id:5, nx:14/28, ny:1-10.5/35 },
    { id:6, nx:14/28, ny:1-24.5/35 },
  ];
  const pegNX = 14/28, pegNY = 1-17.5/35;

  // Detect format: snapshot format has `positions` + `annotations`; hardcoded has `balls` + `arrows` + `labels`
  const isSnapshot = !!src.positions || !!src.annotations;

  // Build arrow marker colours
  let arrowColors = [];
  if (isSnapshot) {
    arrowColors = [...new Set((src.annotations || []).filter(a => a.type === "arrow").map(a => a.color))];
  } else {
    arrowColors = [...new Set((src.arrows || []).map(a => a.color))];
  }

  return (
    <div style={{ marginTop: 12, borderRadius: 8, overflow: "hidden", border: `1px solid ${T.green}44`, height: "100%", display: "flex", flexDirection: "column" }}>
      <svg viewBox={`0 0 ${VW} ${VH}`} style={{ width: "100%", flex: 1, display: "block", minHeight: 0 }}>
        <defs>
          {arrowColors.map(c => (
            <marker key={c} id={`sd-ah-${c.replace('#','')}`} markerWidth="5" markerHeight="5" refX="4" refY="2.5" orient="auto">
              <path d="M0,0 L0,5 L5,2.5 z" fill={c} />
            </marker>
          ))}
        </defs>

        {/* Grass */}
        <GrassPattern style={grassStyle} color={grassColor} vw={VW} vh={VH} />
        <GrassBladesOverlay length={grassLength} color={grassColor} vw={VW} vh={VH} />
        <GrubCastingsOverlay level={grubLevel || "none"} vw={VW} vh={VH} />
        <WaterOverlay level={waterLevel || "none"} vw={VW} vh={VH} />
        <rect x={1} y={1} width={VW-2} height={VH-2} fill="none" stroke={pal.border} strokeWidth={2} />

        {/* Yard-line inner boundary */}
        <rect x={ydU} y={ydU} width={VW-2*ydU} height={VH-2*ydU} fill="none" stroke="#2D6B45" strokeWidth={0.6} strokeDasharray="3 2" opacity={0.5} />
        {/* Corner pegs */}
        {(() => { const r = 1.6;
          return [[ydU+1,r],[r,ydU+1],[VW-ydU-1,r],[VW-r,ydU+1],[ydU+1,VH-r],[r,VH-ydU-1],[VW-ydU-1,VH-r],[VW-r,VH-ydU-1]].map(([cx,cy],i) => (
            <circle key={`cp${i}`} cx={cx} cy={cy} r={r} fill="#fff" stroke="#1A4A2E" strokeWidth={0.4} />
          ));
        })()}

        {/* Baulk lines */}
        {(() => {
          const aY = (1 - 1/35) * VH, bY = (1 - 34/35) * VH, midX = 0.5 * VW;
          return <>
            <line x1={0} y1={aY} x2={midX} y2={aY} stroke="#2D6B45" strokeWidth={1} strokeDasharray="5 3" opacity={0.7} />
            <text x={4} y={aY - 2} fontSize={5.5} fill="#2D6B45" opacity={0.8} fontWeight="600">A</text>
            <line x1={midX} y1={bY} x2={VW} y2={bY} stroke="#2D6B45" strokeWidth={1} strokeDasharray="5 3" opacity={0.7} />
            <text x={VW - 4} y={bY - 2} fontSize={5.5} fill="#2D6B45" opacity={0.8} fontWeight="600" textAnchor="end">B</text>
          </>;
        })()}

        {/* Hoops — hoop 1 blue crown, hoop 5 red crown, rest white */}
        {hoops.map(h => {
          const hx = h.nx*VW, hy = h.ny*VH, hw = 5, legH = 4;
          const crown = h.id === 1 ? "#185FA5" : h.id === 5 ? "#B83232" : "#fff";
          return (
            <g key={h.id}>
              <line x1={hx-hw} y1={hy} x2={hx-hw} y2={hy+legH} stroke="#fff" strokeWidth={2} strokeLinecap="round"/>
              <line x1={hx+hw} y1={hy} x2={hx+hw} y2={hy+legH} stroke="#fff" strokeWidth={2} strokeLinecap="round"/>
              <line x1={hx-hw} y1={hy} x2={hx+hw} y2={hy}       stroke={crown} strokeWidth={2} strokeLinecap="round"/>
            </g>
          );
        })}

        {/* Peg */}
        <circle cx={pegNX*VW} cy={pegNY*VH} r={3} fill="#fff" stroke="#aaa" strokeWidth={1} />

        {isSnapshot ? (
          // ── Snapshot format rendering ──────────────────────────────────────
          <>
            {/* Annotations from recorder */}
            {(src.annotations || []).map((a, i) => {
              const scale = 1; // positions are already in SVG coords (0..VW, 0..VH) — but recorder uses 280px, we use 220px
              const s = VW / 280; // scale factor from recorder VW to StrategyDiagram VW
              const sw = Math.max(1, (a.sw ?? 2) * s);
              const dash = a.ls === "dashed" ? `${sw*3} ${sw*2}` : a.ls === "dotted" ? `${sw} ${sw*2}` : a.ls === "march" ? `${sw*4} ${sw*2}` : a.ls === "flow" ? `${sw} ${sw*2}` : "none";
              const animStyle = a.ls === "march" ? { animation: `march ${animDuration(a,"march")} linear infinite` } : a.ls === "flow" ? { animation: `flow ${animDuration(a,"flow")} linear infinite` } : {};
              const bk = Object.keys(BALL_COLORS_STATIC).find(k => BALL_COLORS_STATIC[k] === a.color) || null;
              const markerId = bk ? `sd-ah-${BALL_COLORS_STATIC[bk].replace('#','')}` : `sd-ah-${a.color.replace('#','')}`;
              if (a.type === "arrow") return (
                <line key={i} x1={a.x1*s} y1={a.y1*s} x2={a.x2*s} y2={a.y2*s}
                  stroke={a.color} strokeWidth={sw} strokeDasharray={dash} style={animStyle}
                  markerEnd={`url(#${markerId})`} />
              );
              if (a.type === "wire") {
                const wDash = `${Math.max(4,sw*2.5)} ${Math.max(3,sw*1.5)}`;
                const angle = Math.atan2(a.y2-a.y1, a.x2-a.x1);
                const tl = Math.max(5,sw*2.5);
                const px = Math.sin(angle)*tl, py = -Math.cos(angle)*tl;
                return (
                  <g key={i} opacity={0.85}>
                    <line x1={a.x1*s} y1={a.y1*s} x2={a.x2*s} y2={a.y2*s} stroke={a.color} strokeWidth={sw} strokeDasharray={wDash} strokeLinecap="round" />
                    <line x1={(a.x1-px)*s} y1={(a.y1-py)*s} x2={(a.x1+px)*s} y2={(a.y1+py)*s} stroke={a.color} strokeWidth={sw} strokeLinecap="round"/>
                    <line x1={(a.x2-px)*s} y1={(a.y2-py)*s} x2={(a.x2+px)*s} y2={(a.y2+py)*s} stroke={a.color} strokeWidth={sw} strokeLinecap="round"/>
                  </g>
                );
              }
              if (a.type === "circle") return (
                <circle key={i} cx={a.cx*s} cy={a.cy*s} r={a.r*s}
                  fill={a.color} fillOpacity={0.25} stroke={sw>0?a.color:"none"} strokeWidth={sw} strokeDasharray={dash} style={animStyle} />
              );
              if (a.type === "rect") return (
                <rect key={i} transform={`rotate(${a.rotation||0},${a.cx*s},${a.cy*s})`}
                  x={(a.cx-a.w/2)*s} y={(a.cy-a.h/2)*s} width={a.w*s} height={a.h*s}
                  fill={a.color} fillOpacity={0.25} stroke={sw>0?a.color:"none"} strokeWidth={sw} strokeDasharray={dash} rx={2} style={animStyle} />
              );
              if (a.type === "triangle") return (
                <polygon key={i} transform={`rotate(${a.rotation||0},${a.cx*s},${a.cy*s})`}
                  points={`${a.cx*s},${(a.cy-a.r)*s} ${(a.cx+a.r*0.87)*s},${(a.cy+a.r*0.5)*s} ${(a.cx-a.r*0.87)*s},${(a.cy+a.r*0.5)*s}`}
                  fill={a.color} fillOpacity={0.25} stroke={sw>0?a.color:"none"} strokeWidth={sw} strokeDasharray={dash} style={animStyle} />
              );
              if (a.type === "quad") {
                const cx = (a.p0.x+a.p1.x+a.p2.x+a.p3.x)/4, cy = (a.p0.y+a.p1.y+a.p2.y+a.p3.y)/4;
                return (
                  <polygon key={i} transform={`rotate(${a.rotation||0},${cx*s},${cy*s})`}
                    points={`${a.p0.x*s},${a.p0.y*s} ${a.p1.x*s},${a.p1.y*s} ${a.p2.x*s},${a.p2.y*s} ${a.p3.x*s},${a.p3.y*s}`}
                    fill={a.color} fillOpacity={0.25} stroke={sw>0?a.color:"none"} strokeWidth={sw} strokeDasharray={dash} style={animStyle} />
                );
              }
              if (a.type === "text") return (
                <text key={i} x={a.cx*s} y={a.cy*s} fontSize={(a.fontSize||12)*s} fill={a.color} textAnchor="middle" fontWeight="600">{a.text}</text>
              );
              return null;
            })}
            {/* Balls from snapshot positions */}
            {Object.entries(src.positions || {}).map(([ball, pos]) => {
              const TRAY_H_REC = 36, VH_REC = Math.round(280 * 35/28) + 36;
              const s = VW / 280;
              const bx = pos.x * 280 * s, by = pos.y * VH_REC * s;
              return (
                <g key={ball}>
                  <circle cx={bx} cy={by} r={6*s} fill={BALL_COLORS_STATIC[ball] || "#888"} />
                </g>
              );
            })}
          </>
        ) : (
          // ── Hardcoded format rendering ─────────────────────────────────────
          <>
            {(src.arrows || []).map((a, i) => (
              <line key={i} x1={a.x1*VW} y1={a.y1*VH} x2={a.x2*VW} y2={a.y2*VH}
                stroke={a.color} strokeWidth={1.5}
                markerEnd={`url(#sd-ah-${a.color.replace('#','')})`} opacity={0.85} />
            ))}
            {(src.labels || []).map((l, i) => (
              <text key={i} x={l.nx*VW} y={l.ny*VH} fontSize={6.5} fill={l.color} textAnchor="middle" fontWeight="600" opacity={0.9}>{l.text}</text>
            ))}
            {(src.balls || []).map((b, i) => (
              <circle key={i} cx={b.nx*VW} cy={b.ny*VH} r={6} fill={b.color} />
            ))}
          </>
        )}
      </svg>
    </div>
  );
}
const STRATEGY_GAME = {
  variant: "AC", colours: "1st",
  currentTurn: null, turnCount: 0, maxHoops: 12,
  pegged: { blue: false, black: false, red: false, yellow: false },
  progress: { blue: 0, black: 0, red: 0, yellow: 0 },
};

function StrategyDiagramEditor({ cardTitle, defaultDiagram, onClose, grassStyle, grassColor, grubLevel = "none", waterLevel = "none" }) {
  const key = strategyDiagramKey(cardTitle);

  // Load existing custom data if any
  const existing = React.useMemo(() => {
    try { const s = localStorage.getItem(key); return s ? JSON.parse(s) : null; } catch { return null; }
  }, [key]);

  // Convert hardcoded diagram to snapshot format for initial positions
  // Balls use normalised coords (nx, ny); we need to map to recorder's SVG coords
  const REC_VW = 280, REC_VH_LAWN = Math.round(280 * 35/28), REC_TRAY_H = 36;
  const REC_VH = REC_VH_LAWN + REC_TRAY_H;

  const initPositions = React.useMemo(() => {
    if (existing) return existing.positions || null;
    if (!defaultDiagram || defaultDiagram.positions) return null; // already snapshot format
    const pos = {};
    (defaultDiagram.balls || []).forEach(b => {
      const colorKey = Object.keys(BALL_COLORS_STATIC).find(k => BALL_COLORS_STATIC[k] === b.color);
      if (colorKey) {
        // nx/ny are normalised 0-1; recorder positions are also normalised 0-1 of its VW/VH
        // ny in diagram: 0=south/bottom, 1=north/top; recorder: y increases downward
        // recorder y fraction = tray + lawn: lawn portion = ny * (LAWN_H/VH)
        const lawny = (1 - b.ny) * (REC_VH_LAWN / REC_VH) + (REC_TRAY_H / REC_VH);
        pos[colorKey] = { x: b.nx, y: lawny };
      }
    });
    return Object.keys(pos).length > 0 ? pos : null;
  }, [existing, defaultDiagram]);

  const initAnnotations = existing ? existing.annotations || [] : [];
  const initNote = existing ? existing.note || "" : "";

  function handleSave(snapshot) {
    localStorage.setItem(key, JSON.stringify(snapshot));
    onClose(true); // true = diagram was updated
  }

  function handleReset() {
    if (!window.confirm("Reset this diagram to the default? Your custom version will be deleted.")) return;
    localStorage.removeItem(key);
    onClose(true);
  }

  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 200, background: "rgba(0,0,0,0.55)", display: "flex", alignItems: "flex-start", justifyContent: "center", padding: "0", overflowY: "auto" }}>
      <div style={{ width: "100%", maxWidth: 440, background: T.pageBg, borderRadius: "0 0 16px 16px", padding: "0 0 2rem", minHeight: "100vh" }}>
        <PageHeader height={72} label="Edit diagram" title={cardTitle}>
          <div style={{ display: "flex", gap: 6, marginLeft: 12 }}>
            {existing && (
              <Btn variant="ghost" size="sm" onClick={handleReset}
                style={{ color: "rgba(255,255,255,0.85)", borderColor: "rgba(255,255,255,0.3)", background: "transparent", fontSize: 11 }}>
                <i className="ti ti-refresh" /> Reset
              </Btn>
            )}
            <button onClick={() => onClose(false)} style={{ background: "none", border: "none", cursor: "pointer", color: "rgba(255,255,255,0.85)", padding: "6px 8px", fontSize: 18, lineHeight: 1 }}>×</button>
          </div>
        </PageHeader>
        <div style={{ padding: "0 1rem" }}>
          <BallPositionRecorder
            game={STRATEGY_GAME}
            onSave={handleSave}
            onCancel={() => onClose(false)}
            grassStyle={grassStyle}
            grassColor={grassColor}
            initialPositions={initPositions}
            initialPosV={existing ? (existing.posV || null) : null}
            initialAnnotations={initAnnotations}
            initialNote={initNote}
          />
        </div>
      </div>
    </div>
  );
}

function StrategyView({ onBack, grassStyle = "diamond", grassColor = "green", grassLength = "none", grubLevel = "none", waterLevel = "none", scene = "none" }) {
  const wide = useWideLayout();
  const [cards, setCards] = useState(() => {
    try { return JSON.parse(localStorage.getItem("strategyCustomCards") || "[]"); } catch { return []; }
  });
  const [expandedCard, setExpandedCard] = useState(null);
  const [activeBook, setActiveBook] = useState("General");
  // User-created books (beyond the built-in AC / GC / General / Drills shelves)
  const [customBooks, setCustomBooks] = useState(() => {
    try { return JSON.parse(localStorage.getItem("strategyCustomBooks") || "[]"); } catch { return []; }
  });
  const [addingBook, setAddingBook] = useState(false);
  const [newBookName, setNewBookName] = useState("");
  function handleAddBook() {
    const name = newBookName.trim();
    if (!name) return;
    const id = "book_" + Date.now().toString(36);
    const updated = [...customBooks, { id, label: name }];
    setCustomBooks(updated);
    localStorage.setItem("strategyCustomBooks", JSON.stringify(updated));
    setNewBookName(""); setAddingBook(false);
    setActiveBook(id);
  }
  const [selectedCard, setSelectedCard] = useState(null); // { card, section } for fullscreen modal
  const [addingCard, setAddingCard] = useState(false);
  const [newTitle, setNewTitle] = useState("");
  const [newBody, setNewBody] = useState("");
  const [editingId, setEditingId] = useState(null);

  function saveCustomCards(updated) {
    setCards(updated);
    localStorage.setItem("strategyCustomCards", JSON.stringify(updated));
  }

  function handleAddCard() {
    if (!newTitle.trim()) return;
    const updated = [...cards, { id: Date.now().toString(), title: newTitle.trim(), body: newBody.trim() }];
    saveCustomCards(updated);
    setNewTitle(""); setNewBody(""); setAddingCard(false);
  }

  function handleDeleteCard(id) {
    saveCustomCards(cards.filter(c => c.id !== id));
    if (expandedCard === id) setExpandedCard(null);
  }

  const [expandedSections, setExpandedSections] = useState({});
  const [selectedOpening, setSelectedOpening] = useState(null);
  const [editingDiagram, setEditingDiagram] = useState(null); // { title, diagram } | null
  const [diagramVersion, setDiagramVersion] = useState(0);   // bump to force re-read from localStorage

  function toggleSection(key) {
    setExpandedSections(prev => ({ ...prev, [key]: !prev[key] }));
  }

  // Custom drills live in their own store; reload when the drills section changes.
  const [drillVersion, setDrillVersion] = useState(0);
  const libDrills = React.useMemo(() => allLibraryDrills(), [drillVersion]);

  const sectionsWithCustom = STRATEGY_SECTIONS.map(s => {
    if (s.key === "custom") return { ...s, cards: cards };
    if (s.key === "drills") return { ...s, cards: libDrills.map(d => ({ ...d, id: d.id, title: d.title, body: d.body })) };
    return s;
  }).concat(
    // Each user-created book gets a placeholder section so the shelf shows up
    customBooks.map(cb => ({
      key: "book_section_" + cb.id,
      label: cb.label,
      desc: "Your own shelf — add chapters and notes here.",
      icon: "ti-book",
      color: "#8B5E3C",
      bg: "#F5EEE6",
      cards: [],
      editable: true,
      book: cb.id,
    }))
  );

  // Add a custom drill to the Library's drills store.
  const [addingDrill, setAddingDrill] = useState(false);
  const [newDrillTitle, setNewDrillTitle] = useState("");
  const [newDrillBody, setNewDrillBody] = useState("");
  function handleAddDrill() {
    if (!newDrillTitle.trim()) return;
    const list = loadCustomDrills();
    list.push({ id: "d_" + Date.now().toString(36), section: "My Drills", title: newDrillTitle.trim(), body: newDrillBody.trim(), metrics: [] });
    saveCustomDrills(list);
    setNewDrillTitle(""); setNewDrillBody(""); setAddingDrill(false);
    setDrillVersion(v => v + 1);
  }
  function handleDeleteDrill(id) {
    saveCustomDrills(loadCustomDrills().filter(d => d.id !== id));
    setDrillVersion(v => v + 1);
  }

  const [selectedSection, setSelectedSection] = useState(null);

  // Section detail view — mobile only (wide mode shows it inline in the right panel)
  if (selectedSection && !wide) {
    const section = sectionsWithCustom.find(s => s.key === selectedSection);
    return (
      <div style={{ background: T.pageBg, minHeight: "100vh" }}>
        <PageHeader height={72} title={section.label} onBack={() => setSelectedSection(null)} />
        <div style={{ maxWidth: 640, margin: "0 auto", padding: "1rem 1rem 3rem" }}>

          {/* Section colour bar header */}
          <div style={{ background: section.color, borderRadius: 12, padding: "14px 16px", marginBottom: 16, display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ width: 36, height: 36, borderRadius: 10, background: "rgba(255,255,255,0.18)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
              <i className={`ti ${section.icon}`} style={{ fontSize: 18, color: "#fff" }} aria-hidden="true" />
            </div>
            <div>
              <p style={{ margin: 0, fontSize: 14, fontWeight: 700, color: "#fff" }}>{section.label}</p>
              <p style={{ margin: 0, fontSize: 11, color: "rgba(255,255,255,0.65)" }}>{section.cards.length} {section.cards.length === 1 ? "card" : "cards"}</p>
            </div>
          </div>

          {/* Card list */}
          <div style={{ display: "grid", gap: 6 }}>
            {section.cards.length === 0 && !section.editable && !section.isDrills && (
              <div style={{ textAlign: "center", padding: "2rem 1rem", color: T.textFaint, fontSize: 13, background: T.card, borderRadius: 10, border: `1px solid ${T.cardBorder}` }}>
                No cards yet
              </div>
            )}

            {/* Drills section — grouped by drill category, with delete for custom */}
            {section.isDrills ? (() => {
              const groups = {};
              section.cards.forEach(c => { const g = c.section || "Drills"; (groups[g] = groups[g] || []).push(c); });
              return Object.entries(groups).map(([groupName, drills]) => (
                <div key={groupName} style={{ marginBottom: 4 }}>
                  <p style={{ margin: "6px 2px 4px", fontSize: 10, fontWeight: 700, color: T.textFaint, letterSpacing: "0.07em", textTransform: "uppercase" }}>{groupName}</p>
                  <div style={{ display: "grid", gap: 6 }}>
                    {drills.map(card => (
                      <div key={card.id} style={{ background: T.card, border: `1px solid ${T.cardBorder}`, borderRadius: 10, overflow: "hidden", boxShadow: "0 1px 3px rgba(26,74,46,0.06)", display: "flex", alignItems: "stretch" }}>
                        <button onClick={() => setSelectedCard({ card, section })}
                          style={{ flex: 1, display: "flex", alignItems: "center", gap: 10, padding: "12px 14px", background: "none", border: "none", cursor: "pointer", textAlign: "left", minWidth: 0 }}>
                          <div style={{ width: 4, alignSelf: "stretch", borderRadius: 2, background: section.color, flexShrink: 0, minHeight: 20 }} />
                          <span style={{ flex: 1, fontSize: 14, fontWeight: 600, color: T.text, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{card.title}</span>
                          {card.metrics && card.metrics.length > 0 && <i className="ti ti-chart-bar" style={{ fontSize: 11, color: T.textFaint, flexShrink: 0 }} aria-hidden="true" title="Has trackable metrics" />}
                          <i className="ti ti-chevron-right" style={{ fontSize: 13, color: T.textFaint, flexShrink: 0 }} aria-hidden="true" />
                        </button>
                        {card.custom && (
                          <button onClick={() => handleDeleteDrill(card.id)} aria-label="Delete drill"
                            style={{ background: "none", border: "none", borderLeft: `1px solid ${T.cardBorder}`, cursor: "pointer", color: T.textFaint, padding: "0 12px", flexShrink: 0 }}>
                            <i className="ti ti-trash" style={{ fontSize: 14 }} aria-hidden="true" />
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              ));
            })() : section.cards.map((card, i) => {
              const cardId = `${section.key}-${card.id || i}`;
              const isOpen = expandedCard === cardId;
              const hardcodedDiagram = OPENING_DIAGRAMS[card.title] || LEAVE_DIAGRAMS[card.title];
              const hasCustomDiagram = (() => { try { return !!localStorage.getItem(strategyDiagramKey(card.title)); } catch { return false; } })();
              const hasDiagram = hardcodedDiagram || hasCustomDiagram;
              const isCustomCard = section.editable;

              return (
                <div key={cardId} style={{ background: T.card, border: `1px solid ${T.cardBorder}`, borderRadius: 10, overflow: "hidden", boxShadow: "0 1px 3px rgba(26,74,46,0.06)" }}>
                  <button onClick={() => setSelectedCard({ card, section })}
                    style={{ width: "100%", display: "flex", alignItems: "center", gap: 10, padding: "12px 14px", background: "none", border: "none", cursor: "pointer", textAlign: "left" }}>
                    <div style={{ width: 4, alignSelf: "stretch", borderRadius: 2, background: section.color, flexShrink: 0, minHeight: 20 }} />
                    <span style={{ flex: 1, fontSize: 14, fontWeight: 600, color: T.text }}>{card.title}</span>
                    {hasDiagram && <i className="ti ti-map-pin" style={{ fontSize: 11, color: T.textFaint, flexShrink: 0 }} aria-hidden="true" />}
                    <i className="ti ti-chevron-right" style={{ fontSize: 13, color: T.textFaint, flexShrink: 0 }} aria-hidden="true" />
                  </button>
                </div>
              );
            })}

            {/* Add drill (drills section) */}
            {section.isDrills && !addingDrill && (
              <button onClick={() => setAddingDrill(true)}
                style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 14px", background: "transparent", border: `1.5px dashed ${T.lawn}`, borderRadius: 10, cursor: "pointer", color: section.color, fontSize: 13, fontWeight: 600, marginTop: 4 }}>
                <i className="ti ti-plus" aria-hidden="true" /> Add your own drill
              </button>
            )}
            {section.isDrills && addingDrill && (
              <div style={{ background: T.card, border: `1px solid ${T.cardBorder}`, borderRadius: 10, padding: "14px" }}>
                <input value={newDrillTitle} onChange={e => setNewDrillTitle(e.target.value)}
                  placeholder="Drill name (e.g. Rush from 10 yards)" autoFocus
                  style={{ width: "100%", marginBottom: 8, fontSize: 14, fontWeight: 600, padding: "8px 10px", borderRadius: 7, border: `1px solid ${T.cardBorder}` }} />
                <textarea value={newDrillBody} onChange={e => setNewDrillBody(e.target.value)}
                  placeholder="Describe the drill — setup, reps, goal…" rows={3}
                  style={{ width: "100%", resize: "vertical", fontSize: 13, padding: "8px 10px", borderRadius: 7, border: `1px solid ${T.cardBorder}`, lineHeight: 1.55, fontFamily: "inherit" }} />
                <div style={{ display: "flex", gap: 8, marginTop: 10, justifyContent: "flex-end" }}>
                  <Btn variant="ghost" size="sm" onClick={() => { setAddingDrill(false); setNewDrillTitle(""); setNewDrillBody(""); }}>Cancel</Btn>
                  <Btn variant="primary" size="sm" onClick={handleAddDrill}>Save drill</Btn>
                </div>
              </div>
            )}

            {/* Add card (editable sections) */}
            {section.editable && !addingCard && (
              <button onClick={() => setAddingCard(true)}
                style={{ display: "flex", alignItems: "center", gap: 8, padding: "10px 14px", background: "transparent", border: `1.5px dashed ${T.lawn}`, borderRadius: 10, cursor: "pointer", color: T.greenMid, fontSize: 13, fontWeight: 600 }}>
                <i className="ti ti-plus" aria-hidden="true" /> Add card
              </button>
            )}
            {section.editable && addingCard && (
              <div style={{ background: T.card, border: `1px solid ${T.cardBorder}`, borderRadius: 10, padding: "14px" }}>
                <input value={newTitle} onChange={e => setNewTitle(e.target.value)}
                  placeholder="Title"
                  style={{ width: "100%", marginBottom: 8, fontSize: 14, fontWeight: 600, padding: "8px 10px", borderRadius: 7, border: `1px solid ${T.cardBorder}` }} />
                <textarea value={newBody} onChange={e => setNewBody(e.target.value)}
                  placeholder="Notes… (optional)" rows={3}
                  style={{ width: "100%", resize: "none", fontSize: 13, padding: "8px 10px", borderRadius: 7, border: `1px solid ${T.cardBorder}`, lineHeight: 1.55 }} />
                {newTitle.trim() && (() => {
                  const hasDiag = (() => { try { return !!localStorage.getItem(strategyDiagramKey(newTitle.trim())); } catch { return false; } })();
                  return (
                    <button onClick={() => setEditingDiagram({ title: newTitle.trim(), diagram: null })}
                      style={{ marginTop: 8, fontSize: 11, color: T.greenMid, background: "none", border: `1px solid ${T.greenMid}`, borderRadius: 5, cursor: "pointer", padding: "3px 8px", display: "flex", alignItems: "center", gap: 4 }}>
                      <i className={`ti ${hasDiag ? "ti-pencil" : "ti-map-pin"}`} aria-hidden="true" />
                      {hasDiag ? "Edit diagram" : "Add diagram"}
                    </button>
                  );
                })()}
                <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
                  <Btn variant="ghost" size="sm" onClick={() => { setAddingCard(false); setNewTitle(""); setNewBody(""); }}>Cancel</Btn>
                  <Btn variant="primary" size="sm" onClick={handleAddCard}>Save</Btn>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Diagram editor modal */}
        {editingDiagram && (
          <StrategyDiagramEditor
            cardTitle={editingDiagram.title}
            defaultDiagram={editingDiagram.diagram}
            onClose={updated => { setEditingDiagram(null); if (updated) setDiagramVersion(v => v + 1); }}
            grassStyle={grassStyle}
            grassColor={grassColor}
          />
        )}

        {/* Fullscreen card modal */}
        {selectedCard && ReactDOM.createPortal((() => {
          const { card: sc, section: ss } = selectedCard;
          const cards = ss.cards || [];
          const cardIdx = cards.findIndex(c => (c.id != null ? c.id === sc.id : c.title === sc.title));
          const hasPrev = cardIdx > 0;
          const hasNext = cardIdx < cards.length - 1;
          function goTo(idx) {
            const next = cards[idx];
            setSelectedCard({ card: next, section: ss });
          }
          const hcDiag = OPENING_DIAGRAMS[sc.title] || LEAVE_DIAGRAMS[sc.title];
          const hasCustDiag = (() => { try { return !!localStorage.getItem(strategyDiagramKey(sc.title)); } catch { return false; } })();
          const hasDiag = hcDiag || hasCustDiag;
          return (
            <div onClick={() => setSelectedCard(null)} style={{ position: "fixed", inset: 0, zIndex: 600, background: "rgba(0,0,0,0.5)", display: "flex", flexDirection: "column", padding: "48px 10px 10px" }}>
              <div onClick={e => e.stopPropagation()} style={{ flex: 1, background: T.pageBg, borderRadius: 16, display: "flex", flexDirection: "column", overflow: "hidden", boxShadow: "0 8px 40px rgba(0,0,0,0.3)", minHeight: 0 }}>
              {/* Header */}
              <div style={{ background: ss.color, padding: "0 14px", display: "flex", alignItems: "center", gap: 10, flexShrink: 0, minHeight: 52, borderRadius: "16px 16px 0 0" }}>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <p style={{ margin: 0, fontSize: 15, fontWeight: 700, color: "#fff", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{sc.title}</p>
                  <p style={{ margin: 0, fontSize: 11, color: "rgba(255,255,255,0.65)" }}>{ss.label} · {cardIdx + 1} / {cards.length}</p>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 6, flexShrink: 0 }}>
                  {ss.editable && (
                    <button onClick={() => { handleDeleteCard(sc.id); setSelectedCard(null); }}
                      style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, color: "#fff", width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer" }}>
                      <i className="ti ti-trash" style={{ fontSize: 15 }} aria-hidden="true" />
                    </button>
                  )}
                  <button onClick={() => hasPrev && goTo(cardIdx - 1)}
                    style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, color: "#fff", width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", cursor: hasPrev ? "pointer" : "default", opacity: hasPrev ? 1 : 0.35 }}>
                    <i className="ti ti-chevron-left" style={{ fontSize: 16 }} aria-hidden="true" />
                  </button>
                  <button onClick={() => hasNext && goTo(cardIdx + 1)}
                    style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, color: "#fff", width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", cursor: hasNext ? "pointer" : "default", opacity: hasNext ? 1 : 0.35 }}>
                    <i className="ti ti-chevron-right" style={{ fontSize: 16 }} aria-hidden="true" />
                  </button>
                </div>
              </div>
              {/* Body — flex column, diagram and text each get proportional space */}
              <div style={{ flex: 1, minHeight: 0, display: "flex", flexDirection: "column", padding: "16px 16px 20px", gap: 12 }}>
                {sc.isometric ? (
                  <>
                    <div style={{ flex: "1 1 0", minHeight: 0, display: "flex", alignItems: "stretch" }}>
                      <IsometricLawnDiagram data={sc.isometric} grassStyle={grassStyle} grassColor={grassColor} scene={scene} grubLevel={grubLevel} waterLevel={waterLevel} />
                    </div>
                    {sc.body && <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.6, flexShrink: 0 }}>{sc.body}</p>}
                  </>
                ) : sc.animated ? (
                  <>
                    <div style={{ flex: "1 1 0", minHeight: 0, display: "flex", alignItems: "stretch" }}>
                      <AnimatedIsometricDiagram data={sc.animated} grassStyle={grassStyle} grassColor={grassColor} scene={scene} grubLevel={grubLevel} waterLevel={waterLevel} />
                    </div>
                    {sc.body && <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.6, flexShrink: 0 }}>{sc.body}</p>}
                  </>
                ) : hasDiag ? (
                  <>
                    <div style={{ flex: "1 1 0", minHeight: 0 }}>
                      <StrategyDiagram key={`${sc.title}-${diagramVersion}`} diagram={hcDiag || null} title={sc.title} grassStyle={grassStyle} grassColor={grassColor} grassLength={grassLength} grubLevel={grubLevel} waterLevel={waterLevel} scene={scene} />
                    </div>
                    <div style={{ flexShrink: 0, display: "flex", flexDirection: "column", gap: 8 }}>
                      <button onClick={() => setEditingDiagram({ title: sc.title, diagram: hcDiag || null })}
                        style={{ fontSize: 12, color: T.greenMid, background: "none", border: `1px solid ${T.greenMid}`, borderRadius: 6, cursor: "pointer", padding: "5px 12px", display: "inline-flex", alignItems: "center", gap: 5, alignSelf: "flex-start" }}>
                        <i className="ti ti-pencil" aria-hidden="true" /> Edit diagram
                      </button>
                      {sc.body && <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.6 }}>{sc.body}</p>}
                    </div>
                  </>
                ) : (
                  <>
                    {sc.body && <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.7 }}>{sc.body}</p>}
                    {ss.editable && (
                      <button onClick={() => setEditingDiagram({ title: sc.title, diagram: null })}
                        style={{ fontSize: 12, color: T.greenMid, background: "none", border: `1px solid ${T.greenMid}`, borderRadius: 6, cursor: "pointer", padding: "5px 12px", display: "inline-flex", alignItems: "center", gap: 5, alignSelf: "flex-start" }}>
                        <i className="ti ti-map-pin" aria-hidden="true" /> Add diagram
                      </button>
                    )}
                  </>
                )}
              </div>
            </div>
            </div>
          );
        })(), document.body)}
      </div>
    );
  }

  return (
    <div style={{ background: T.pageBg, minHeight: "100vh" }}>
      <PageHeader height={72} label="Croquet? OK!" title="Library" onBack={onBack} />

      <div style={{ maxWidth: wide ? 1200 : 640, margin: "0 auto", padding: "1rem 1rem 3rem" }}>

        {/* Editorial intro */}
        {!wide && (
        <div style={{ marginBottom: 16, padding: "2px 2px 14px", borderBottom: `1px solid ${T.cardBorder}` }}>
          <p style={{ margin: 0, fontSize: 11, fontWeight: 700, letterSpacing: "0.14em", textTransform: "uppercase", color: T.greenMid }}>The Reading Room</p>
          <h2 style={{ margin: "6px 0 4px", fontSize: 24, fontWeight: 700, color: T.text, fontFamily: "'Libre Baskerville', Georgia, serif", lineHeight: 1.15 }}>
            Study with the greats
          </h2>
          <p style={{ margin: 0, fontSize: 13, color: T.textMuted, lineHeight: 1.5 }}>
            A century of croquet theory sits on these shelves. Read from the masters, borrow your coach&rsquo;s notes, or pen your own volume.
          </p>
        </div>
        )}

        <div style={wide ? { display: "grid", gridTemplateColumns: "260px 1fr", gap: 20, alignItems: "start" } : {}}>

        <div style={wide ? { position: "sticky", top: 16, maxHeight: "calc(100vh - 80px)", overflowY: "auto", display: "flex", flexDirection: "column", gap: 0 } : {}}>

        {/* Books nav — the croquet codes, each a "book" on the shelf */}
        {(() => {
          const BOOKS = [
            { id: "General", label: "General",     icon: "ti-books",     color: "#2D6B45" },
            { id: "AC",      label: "Association", icon: "ti-book-2",    color: "#185FA5" },
            { id: "GC",      label: "Golf",        icon: "ti-golf",      color: "#B83232" },
            { id: "Rules",   label: "Rules",       icon: "ti-gavel",     color: "#7A4F00" },
            { id: "Drills",  label: "Drills",      icon: "ti-target",    color: "#16A34A" },
            ...customBooks.map(cb => ({ id: cb.id, label: cb.label, icon: "ti-book", color: "#8B5E3C" })),
          ].filter(b => sectionsWithCustom.some(s => (s.book || "General") === b.id));
          return (
            <div style={{ display: "flex", gap: 10, marginBottom: 18, flexWrap: "wrap", alignItems: "stretch" }}>
              {BOOKS.map(b => {
                const active = activeBook === b.id;
                return (
                  <button key={b.id} onClick={() => setActiveBook(b.id)}
                    style={{
                      display: "inline-flex", alignItems: "stretch", cursor: "pointer", fontFamily: "inherit",
                      padding: 0, overflow: "hidden", borderRadius: "8px 0 0 8px",
                      background: "linear-gradient(180deg, #FFFDF8 0%, #FBF6EC 100%)",
                      border: `1px solid ${T.cardBorder}`,
                      borderRight: "2px solid #fff",
                      borderTop: `3px solid ${b.color}`,
                      borderBottom: `3px solid ${b.color}`,
                      boxShadow: active
                        ? `0 3px 10px ${b.color}44, inset 0 0 0 1.5px ${b.color}`
                        : "0 1px 4px rgba(26,74,46,0.08)",
                      transform: active ? "translateY(-1px)" : "none",
                      WebkitTapHighlightColor: "transparent",
                    }}>
                    {/* Coloured spine with page-edge texture, matching the chapter cards */}
                    <div style={{ width: 30, flexShrink: 0, position: "relative",
                      background: `${b.color} repeating-linear-gradient(90deg, rgba(255,255,255,0.10) 0px, rgba(255,255,255,0.10) 1px, rgba(0,0,0,0.06) 1px, rgba(0,0,0,0.06) 3px)`,
                      display: "flex", alignItems: "center", justifyContent: "center",
                      boxShadow: "inset 4px 0 5px rgba(255,255,255,0.12), inset -4px 0 6px rgba(0,0,0,0.20)" }}>
                      <span aria-hidden="true" style={{ position: "absolute", top: 0, bottom: 0, left: 0, width: 3, background: "rgba(0,0,0,0.16)" }} />
                      <i className={`ti ${b.icon}`} style={{ fontSize: 15, color: "rgba(255,255,255,0.95)", zIndex: 1 }} aria-hidden="true" />
                    </div>
                    {/* Cover label */}
                    <span style={{ padding: "8px 14px", fontSize: 14, fontWeight: 700,
                      fontFamily: "'Libre Baskerville', Georgia, serif",
                      color: active ? b.color : "#3A2E1C", display: "flex", alignItems: "center" }}>
                      {b.label}
                    </span>
                  </button>
                );
              })}

              {/* + New book — a blank bookend that opens a tiny inline form */}
              {addingBook ? (
                <div style={{
                  display: "inline-flex", alignItems: "center", gap: 6,
                  padding: "6px 8px 6px 10px", borderRadius: 8,
                  background: "linear-gradient(180deg, #FFFDF8 0%, #FBF6EC 100%)",
                  border: `1px dashed ${T.cardBorder}`,
                  borderTop: "3px solid #8B5E3C", borderBottom: "3px solid #8B5E3C",
                }}>
                  <input
                    autoFocus
                    value={newBookName}
                    onChange={e => setNewBookName(e.target.value)}
                    onKeyDown={e => { if (e.key === "Enter") handleAddBook(); if (e.key === "Escape") { setAddingBook(false); setNewBookName(""); } }}
                    placeholder="Book title…"
                    style={{ border: "none", background: "transparent", outline: "none",
                      fontFamily: "'Libre Baskerville', Georgia, serif", fontSize: 14, fontWeight: 700,
                      color: "#3A2E1C", width: 110 }} />
                  <button onClick={handleAddBook} aria-label="Create book"
                    style={{ border: "none", background: "#8B5E3C", color: "#fff", borderRadius: 6, cursor: "pointer", width: 28, height: 28, display: "inline-flex", alignItems: "center", justifyContent: "center" }}>
                    <i className="ti ti-check" style={{ fontSize: 15 }} aria-hidden="true" />
                  </button>
                  <button onClick={() => { setAddingBook(false); setNewBookName(""); }} aria-label="Cancel"
                    style={{ border: "none", background: "transparent", color: T.textFaint, cursor: "pointer", width: 24, height: 28, display: "inline-flex", alignItems: "center", justifyContent: "center" }}>
                    <i className="ti ti-x" style={{ fontSize: 15 }} aria-hidden="true" />
                  </button>
                </div>
              ) : (
                <button onClick={() => setAddingBook(true)} aria-label="Make a new book"
                  title="Make a new book"
                  style={{
                    display: "inline-flex", alignItems: "center", justifyContent: "center", gap: 6,
                    padding: "0 14px", borderRadius: 8, cursor: "pointer", fontFamily: "inherit",
                    background: "transparent", border: `1px dashed ${T.cardBorder}`,
                    color: T.textMuted, alignSelf: "stretch", minHeight: 44,
                    WebkitTapHighlightColor: "transparent",
                  }}>
                  <i className="ti ti-plus" style={{ fontSize: 18 }} aria-hidden="true" />
                  <span style={{ fontSize: 13.5, fontWeight: 700 }}>New book</span>
                </button>
              )}
            </div>
          );
        })()}

        {/* Chapters in the selected book — clean rows with a book-cover top & bottom edge */}
        <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
          {sectionsWithCustom.filter(s => (s.book || "General") === activeBook).map((section, idx) => {
            const cardCount = section.cards.length;
            const previews = section.cards.slice(0, 3).map(c => c.title);
            return (
              <button key={section.key}
                onClick={() => setSelectedSection(section.key)}
                style={{
                  background: wide && selectedSection === section.key
                    ? `linear-gradient(180deg, ${section.color}18 0%, ${section.color}0a 100%)`
                    : "linear-gradient(180deg, #FFFDF8 0%, #FBF6EC 100%)",
                  border: wide && selectedSection === section.key
                    ? `1.5px solid ${section.color}88`
                    : `1px solid ${T.cardBorder}`,
                  // Cover-style top & bottom edges in the chapter colour
                  borderTop: `4px solid ${section.color}`,
                  borderBottom: `4px solid ${section.color}`,
                  borderRadius: 10, overflow: "hidden", cursor: "pointer",
                  textAlign: "left", padding: 0, width: "100%",
                  boxShadow: wide && selectedSection === section.key ? `0 2px 8px ${section.color}33` : "0 1px 4px rgba(26,74,46,0.08)",
                  display: "flex", alignItems: "stretch",
                  WebkitTapHighlightColor: "transparent",
                }}>
                {/* Coloured spine with chapter number — faint vertical lines read as page edges seen from the top */}
                <div style={{ width: 46, flexShrink: 0, position: "relative",
                  background: `${section.color} repeating-linear-gradient(90deg, rgba(255,255,255,0.10) 0px, rgba(255,255,255,0.10) 1px, rgba(0,0,0,0.06) 1px, rgba(0,0,0,0.06) 3px)`,
                  display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 5, padding: "14px 0",
                  boxShadow: "inset 5px 0 6px rgba(255,255,255,0.12), inset -5px 0 7px rgba(0,0,0,0.20)" }}>
                  {/* cover board edge — slightly darker band at the outer (left) edge */}
                  <span aria-hidden="true" style={{ position: "absolute", top: 0, bottom: 0, left: 0, width: 4, background: "rgba(0,0,0,0.16)" }} />
                  <i className={`ti ${section.icon}`} style={{ fontSize: 18, color: "rgba(255,255,255,0.95)", zIndex: 1 }} aria-hidden="true" />
                  <span style={{ fontSize: 9, fontWeight: 700, color: "rgba(255,255,255,0.72)", letterSpacing: "0.06em", zIndex: 1 }}>{String(idx + 1).padStart(2, "0")}</span>
                </div>
                {/* Body */}
                <div style={{ flex: 1, minWidth: 0, padding: "12px 14px", display: "flex", flexDirection: "column", gap: 5 }}>
                  <span style={{ fontSize: 16, fontWeight: 700, color: "#3A2E1C", fontFamily: "'Libre Baskerville', Georgia, serif", lineHeight: 1.2 }}>{section.label}</span>
                  {section.desc && <span style={{ fontSize: 12, color: "#6B5E48", lineHeight: 1.45 }}>{section.desc}</span>}
                  {previews.length > 0 && (
                    <span style={{ fontSize: 11.5, color: "#9A8A6E", lineHeight: 1.4, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                      {previews.join(" · ")}{cardCount > previews.length ? " · …" : ""}
                    </span>
                  )}
                </div>
                {/* Read affordance */}
                <div style={{ display: "flex", alignItems: "center", paddingRight: 12, color: section.color }}>
                  <i className="ti ti-chevron-right" style={{ fontSize: 18 }} aria-hidden="true" />
                </div>
              </button>
            );
          })}
          {sectionsWithCustom.filter(s => (s.book || "General") === activeBook).length === 0 && (
            <div style={{ padding: "2rem 1rem", textAlign: "center", color: T.textFaint, fontSize: 13, background: T.greenPale, borderRadius: 10, border: `1px dashed ${T.lawn}` }}>
              <i className="ti ti-book-off" style={{ fontSize: 24, display: "block", marginBottom: 8, color: T.greenMid }} aria-hidden="true" />
              No chapters in this book yet.
            </div>
          )}
        </div>
        </div>{/* end left column */}

        {/* ── Right column (wide): section detail inline ── */}
        {wide && (
          <div style={{ background: T.card, border: `1px solid ${T.cardBorder}`, borderRadius: 14, minHeight: 400, overflow: "hidden" }}>
            {selectedSection ? (() => {
              const section = sectionsWithCustom.find(s => s.key === selectedSection);
              if (!section) return null;
              return (
                <div>
                  <div style={{ background: section.color, padding: "14px 18px", display: "flex", alignItems: "center", gap: 12 }}>
                    <div style={{ width: 34, height: 34, borderRadius: 9, background: "rgba(255,255,255,0.18)", display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                      <i className={`ti ${section.icon}`} style={{ fontSize: 17, color: "#fff" }} aria-hidden="true" />
                    </div>
                    <div style={{ flex: 1 }}>
                      <p style={{ margin: 0, fontSize: 15, fontWeight: 700, color: "#fff", fontFamily: "'Libre Baskerville', Georgia, serif" }}>{section.label}</p>
                      <p style={{ margin: 0, fontSize: 11, color: "rgba(255,255,255,0.65)" }}>{section.cards.length} {section.cards.length === 1 ? "card" : "cards"}</p>
                    </div>
                  </div>
                  <div style={{ padding: "14px 16px", display: "flex", flexDirection: "column", gap: 8 }}>
                    {section.cards.map((card, ci) => {
                      const cardId = `${section.key}-${card.id || ci}`;
                      const isOpen = expandedCard === cardId;
                      return (
                        <div key={cardId} style={{ background: T.pageBg, border: `1px solid ${T.cardBorder}`, borderRadius: 10, overflow: "hidden" }}>
                          <button onClick={() => setSelectedCard({ card, section })}
                            style={{ width: "100%", display: "flex", alignItems: "center", gap: 10, padding: "11px 14px", background: "transparent", border: "none", cursor: "pointer", textAlign: "left", fontFamily: "inherit" }}>
                            <i className={`ti ${section.icon}`} style={{ fontSize: 14, color: section.color, flexShrink: 0 }} aria-hidden="true" />
                            <span style={{ flex: 1, fontSize: 13.5, fontWeight: 700, color: T.text, fontFamily: "'Libre Baskerville', Georgia, serif" }}>{card.title}</span>
                            <i className="ti ti-arrow-up-right" style={{ fontSize: 13, color: T.textFaint, flexShrink: 0 }} aria-hidden="true" />
                          </button>
                          {card.body && (
                            <div style={{ padding: "0 14px 12px", fontSize: 13, color: T.textMuted, lineHeight: 1.65 }}>
                              {card.body.slice(0, 220)}{card.body.length > 220 ? "…" : ""}
                            </div>
                          )}
                        </div>
                      );
                    })}
                    {section.cards.length === 0 && (
                      <p style={{ margin: "1.5rem 0", textAlign: "center", fontSize: 13, color: T.textFaint, fontStyle: "italic" }}>No cards in this section yet.</p>
                    )}
                  </div>
                </div>
              );
            })() : (
              <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", minHeight: 400, gap: 10, padding: "2rem" }}>
                <i className="ti ti-books" style={{ fontSize: 36, color: T.greenMid, opacity: 0.4 }} aria-hidden="true" />
                <p style={{ margin: 0, fontSize: 13, color: T.textFaint, textAlign: "center" }}>Select a chapter from the shelf to read it here</p>
              </div>
            )}
          </div>
        )}

        </div>{/* end grid */}
      </div>

      {/* Diagram editor modal */}
      {editingDiagram && (
        <StrategyDiagramEditor
          cardTitle={editingDiagram.title}
          defaultDiagram={editingDiagram.diagram}
          onClose={updated => { setEditingDiagram(null); if (updated) setDiagramVersion(v => v + 1); }}
          grassStyle={grassStyle}
          grassColor={grassColor}
        />
      )}

      {/* Fullscreen card modal — wide mode */}
      {selectedCard && ReactDOM.createPortal((() => {
        const { card: sc, section: ss } = selectedCard;
        const cards = ss.cards || [];
        const cardIdx = cards.findIndex(c => (c.id != null ? c.id === sc.id : c.title === sc.title));
        const hasPrev = cardIdx > 0;
        const hasNext = cardIdx < cards.length - 1;
        function goTo(idx) { setSelectedCard({ card: cards[idx], section: ss }); }
        const hcDiag = OPENING_DIAGRAMS[sc.title] || LEAVE_DIAGRAMS[sc.title];
        const hasCustDiag = (() => { try { return !!localStorage.getItem(strategyDiagramKey(sc.title)); } catch { return false; } })();
        const hasDiag = hcDiag || hasCustDiag;
        return (
          <div onClick={() => setSelectedCard(null)} style={{ position: "fixed", inset: 0, zIndex: 600, background: "rgba(0,0,0,0.5)", display: "flex", flexDirection: "column", padding: "48px 10px 10px" }}>
            <div onClick={e => e.stopPropagation()} style={{ flex: 1, background: T.pageBg, borderRadius: 16, display: "flex", flexDirection: "column", overflow: "hidden", boxShadow: "0 8px 40px rgba(0,0,0,0.3)", minHeight: 0 }}>
              <div style={{ background: ss.color, padding: "0 14px", display: "flex", alignItems: "center", gap: 10, flexShrink: 0, minHeight: 52, borderRadius: "16px 16px 0 0" }}>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <p style={{ margin: 0, fontSize: 15, fontWeight: 700, color: "#fff", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{sc.title}</p>
                  <p style={{ margin: 0, fontSize: 11, color: "rgba(255,255,255,0.65)" }}>{ss.label} · {cardIdx + 1} / {cards.length}</p>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 6, flexShrink: 0 }}>
                  {ss.editable && (
                    <button onClick={() => { handleDeleteCard(sc.id); setSelectedCard(null); }}
                      style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, color: "#fff", width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer" }}>
                      <i className="ti ti-trash" style={{ fontSize: 15 }} aria-hidden="true" />
                    </button>
                  )}
                  <button onClick={() => hasPrev && goTo(cardIdx - 1)}
                    style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, color: "#fff", width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", cursor: hasPrev ? "pointer" : "default", opacity: hasPrev ? 1 : 0.35 }}>
                    <i className="ti ti-chevron-left" style={{ fontSize: 16 }} aria-hidden="true" />
                  </button>
                  <button onClick={() => hasNext && goTo(cardIdx + 1)}
                    style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, color: "#fff", width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", cursor: hasNext ? "pointer" : "default", opacity: hasNext ? 1 : 0.35 }}>
                    <i className="ti ti-chevron-right" style={{ fontSize: 16 }} aria-hidden="true" />
                  </button>
                  <button onClick={() => setSelectedCard(null)}
                    style={{ background: "rgba(255,255,255,0.15)", border: "none", borderRadius: 8, color: "#fff", width: 32, height: 32, display: "flex", alignItems: "center", justifyContent: "center", cursor: "pointer" }}>
                    <i className="ti ti-x" style={{ fontSize: 16 }} aria-hidden="true" />
                  </button>
                </div>
              </div>
              <div style={{ flex: 1, minHeight: 0, display: "flex", flexDirection: "column", padding: "16px 16px 20px", gap: 12, overflowY: "auto" }}>
                {sc.isometric ? (
                  <>
                    <div style={{ flex: "1 1 0", minHeight: 0, display: "flex", alignItems: "stretch" }}>
                      <IsometricLawnDiagram data={sc.isometric} grassStyle={grassStyle} grassColor={grassColor} scene={scene} grubLevel={grubLevel} waterLevel={waterLevel} />
                    </div>
                    {sc.body && <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.6, flexShrink: 0 }}>{sc.body}</p>}
                  </>
                ) : sc.animated ? (
                  <>
                    <div style={{ flex: "1 1 0", minHeight: 0, display: "flex", alignItems: "stretch" }}>
                      <AnimatedIsometricDiagram data={sc.animated} grassStyle={grassStyle} grassColor={grassColor} scene={scene} grubLevel={grubLevel} waterLevel={waterLevel} />
                    </div>
                    {sc.body && <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.6, flexShrink: 0 }}>{sc.body}</p>}
                  </>
                ) : hasDiag ? (
                  <>
                    <div style={{ flex: "1 1 0", minHeight: 0 }}>
                      <StrategyDiagram key={`${sc.title}-${diagramVersion}`} diagram={hcDiag || null} title={sc.title} grassStyle={grassStyle} grassColor={grassColor} grassLength={grassLength} grubLevel={grubLevel} waterLevel={waterLevel} scene={scene} />
                    </div>
                    <div style={{ flexShrink: 0, display: "flex", flexDirection: "column", gap: 8 }}>
                      <button onClick={() => setEditingDiagram({ title: sc.title, diagram: hcDiag || null })}
                        style={{ fontSize: 12, color: T.greenMid, background: "none", border: `1px solid ${T.greenMid}`, borderRadius: 6, cursor: "pointer", padding: "5px 12px", display: "inline-flex", alignItems: "center", gap: 5, alignSelf: "flex-start" }}>
                        <i className="ti ti-pencil" aria-hidden="true" /> Edit diagram
                      </button>
                      {sc.body && <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.6 }}>{sc.body}</p>}
                    </div>
                  </>
                ) : (
                  <p style={{ margin: 0, fontSize: 14, color: T.text, lineHeight: 1.6 }}>{sc.body || <em style={{ color: T.textFaint }}>No content yet.</em>}</p>
                )}
              </div>
            </div>
          </div>
        );
      })(), document.body)}
    </div>
  );
}
