// ── Library drills ──────────────────────────────────────────────────────────
// The Library's "Drills" section combines the built-in drills with any custom
// drills the user adds. Custom drills live in their own store so they're stable
// and independent of the strategy custom cards.
function loadCustomDrills() {
  try { return JSON.parse(localStorage.getItem("libraryDrills") || "[]"); } catch { return []; }
}
function saveCustomDrills(list) {
  try { localStorage.setItem("libraryDrills", JSON.stringify(list)); } catch {}
}
// All drills available to browse and to build sessions from: built-ins (flagged)
// plus the user's custom drills.
function allLibraryDrills() {
  const custom = loadCustomDrills().map(d => ({ ...d, custom: true }));
  return [...BUILTIN_DRILLS, ...custom];
}

