// The coach's own cohort, stored per coach (keyed by the coach's self id) so it
// survives renames. A roster entry references a member: { id, playerId, name }.
// Progress notes are private coach-to-player journal entries. Assignments are a
// drill pushed to a player with a note — groundwork for "did they do it?" once
// players can mark assigned drills done (the practice flow already has an
// "assigned" session type to build on).
function coachKey() { return "coach:" + mySelfId(); }
function loadCoachData() {
  try {
    const d = JSON.parse(localStorage.getItem(coachKey()) || "null") || {};
    return { roster: d.roster || [], notes: d.notes || [], assignments: d.assignments || [] };
  } catch { return { roster: [], notes: [], assignments: [] }; }
}
function saveCoachData(data) {
  const norm = { roster: data.roster || [], notes: data.notes || [], assignments: data.assignments || [] };
  try { localStorage.setItem(coachKey(), JSON.stringify(norm)); } catch {}
}
function makeCoachId(p) { return (p || "cn") + "_" + Math.random().toString(36).slice(2,9) + Date.now().toString(36); }


// Pretty time-window label for a session, e.g. "Fri 21 Jun · 5–7pm", "Today · 5pm",
// or "Anytime" for assigned/unscheduled work.
function sessionTimeLabel(s) {
  if (!s.scheduledDate && !s.startTime) return "Anytime";
  const fmtT = t => {
    if (!t) return "";
    const [h, m] = t.split(":").map(Number);
    const ap = h < 12 ? "am" : "pm";
    const hr = h % 12 === 0 ? 12 : h % 12;
    return m ? `${hr}:${String(m).padStart(2, "0")}${ap}` : `${hr}${ap}`;
  };
  let datePart = "";
  if (s.scheduledDate) {
    const d = new Date(s.scheduledDate + "T00:00:00");
    const today = new Date(); today.setHours(0,0,0,0);
    const diff = Math.round((d - today) / 86400000);
    datePart = diff === 0 ? "Today" : diff === 1 ? "Tomorrow"
      : d.toLocaleDateString("en-AU", { weekday: "short", day: "numeric", month: "short" });
  }
  let timePart = "";
  if (s.startTime && s.endTime) timePart = `${fmtT(s.startTime).replace(/(am|pm)$/, (m) => fmtT(s.endTime).endsWith(m) ? "" : m)}–${fmtT(s.endTime)}`;
  else if (s.startTime) timePart = fmtT(s.startTime);
  return [datePart, timePart].filter(Boolean).join(" · ") || "Anytime";
}

// The next practice session worth surfacing on the home strip: an in-progress
// one, else the soonest scheduled/assigned session that isn't completed. Returns
// null if there's nothing pending.
function nextPracticeSession() {
  try {
    const sessions = (loadPracticeData().sessions || []).filter(s => s.status !== "completed");
    if (!sessions.length) return null;
    const active = sessions.find(s => s.status === "active");
    if (active) return active;
    const todayStr = new Date().toISOString().slice(0, 10);
    const scheduled = sessions
      .filter(s => s.scheduledDate && s.scheduledDate >= todayStr)
      .sort((a, b) => (a.scheduledDate + (a.startTime || "")).localeCompare(b.scheduledDate + (b.startTime || "")));
    if (scheduled.length) return scheduled[0];
    const anytime = sessions.find(s => s.type === "assigned" && !s.scheduledDate) || sessions.find(s => !s.scheduledDate);
    return anytime || null;
  } catch { return null; }
}


// ─── SquadView ──────────────────────────────────────────────────────────────
// A "group" of players that isn't bound to one club and isn't a coaching
// relationship — e.g. an ongoing pennants team, a development squad, a state
// side. One place to organise membership, fixtures, captains, practices,
