function loadSquadData() {
  try {
    const d = JSON.parse(localStorage.getItem("squadData") || "null") || {};
    return { squads: Array.isArray(d.squads) ? d.squads : [], activeId: d.activeId || null };
  } catch { return { squads: [], activeId: null }; }
}

