            const extraClubsByIdx = {
              2: ["Toowong Croquet Club"], 7: ["Toowong Croquet Club"],
              9: ["Kedron-Wavell Croquet Club"], 13: ["Toowong Croquet Club"],
              16: ["Kedron-Wavell Croquet Club"], 11: ["Sandgate Croquet Club"],
            };
            // Upcoming events the member has entered — a mix of home club and away
            // competitions at other clubs, for a lived-in calendar. Dates are
            // generated relative to today so they always read as "upcoming".
            const dPlus = (days) => { const d = new Date(); d.setDate(d.getDate() + days); return d.toISOString().slice(0,10); };
            const EVENT_POOL = [
              { name: "Club Championship Singles", club: clubName,                      code: "AC", offset: 9,  status: "confirmed" },
              { name: "Twilight GC Doubles",       club: clubName,                      code: "GC", offset: 16, status: "confirmed" },
              { name: "Queensland State GC Open",  club: "Toowong Croquet Club",        code: "GC", offset: 23, status: "entered" },
              { name: "Brisbane Inter-Club Pennant",club: "Kedron-Wavell Croquet Club", code: "AC", offset: 30, status: "confirmed" },
              { name: "Handicap Doubles Day",      club: "Sandgate Croquet Club",       code: "GC", offset: 37, status: "waitlist" },
              { name: "Veterans AC Invitational",  club: "Toowong Croquet Club",        code: "AC", offset: 44, status: "entered" },
              { name: "Spring GC Eights",          club: clubName,                      code: "GC", offset: 12, status: "confirmed" },
              { name: "Gold Coast Open Weekend",   club: "Mudgeeraba Croquet Club",     code: "AC", offset: 51, status: "entered" },
            ];
            // Each member gets 0–3 upcoming events depending on how active they are.
            const eventCountByIdx = [3,3,2,3,2,1,2,2,1,2,1,2,1,3,2,3,3,1,2,1];
            // Personal highlights / fun facts.
            const highlightsByIdx = [
              [{ icon:"ti-trophy", label:"Club Champion 2024", detail:"Singles AC" }, { icon:"ti-flame", label:"Best break: 18 hoops", detail:"all-round + peg out" }, { icon:"ti-calendar-star", label:"Hasn't missed a Tuesday in 3 years" }],
              [{ icon:"ti-whistle", label:"Runs the Saturday coaching clinic" }, { icon:"ti-coffee", label:"Makes the best scones in the club" }],
              [{ icon:"ti-target", label:"Lowest GC handicap at the club" }, { icon:"ti-swords", label:"3-time inter-club pennant winner" }],
              [{ icon:"ti-flame", label:"Best break: 12 hoops" }, { icon:"ti-tools", label:"Owns four mallets (and counting)" }],
              [{ icon:"ti-shield", label:"Former pennant captain" }, { icon:"ti-mood-smile", label:"Most sporting player, 2023" }],
              [{ icon:"ti-rocket", label:"Handicap dropped 4 points this year" }],
              [{ icon:"ti-trophy", label:"Most club-day wins, 2024" }, { icon:"ti-bolt", label:"Five-game winning streak" }],
              [{ icon:"ti-book", label:"Keeps a notebook of every break" }],
              [{ icon:"ti-clock-hour-3", label:"27 years a member" }, { icon:"ti-history", label:"Unofficial club historian" }],
              [{ icon:"ti-swords", label:"Beat the Toowong club champ" }],
              [{ icon:"ti-mood-happy", label:"Beats her husband regularly" }],
              [{ icon:"ti-heart-handshake", label:"Working-bee MVP" }],
              [{ icon:"ti-book", label:"Reads more croquet than she plays" }],
              [{ icon:"ti-bolt", label:"Hardest hitter at the club" }, { icon:"ti-confetti", label:"Crowd favourite at tournaments" }],
              [{ icon:"ti-target", label:"Triple-peel specialist" }],
              [{ icon:"ti-gavel", label:"Knows every law by clause number" }, { icon:"ti-award", label:"Referee examiner" }],
              [{ icon:"ti-trophy", label:"Club Champion (x4)" }, { icon:"ti-star", label:"Prettiest swing at the club" }],
              [{ icon:"ti-clipboard-check", label:"Keeps the rolling roster" }],
              [{ icon:"ti-flame", label:"Junior player to watch" }],
              [{ icon:"ti-tools", label:"Hickory mallet older than most members" }],
            ];
            // Spread arrivals across the last ~2.5 hours up to now, so a freshly
